"use strict";
/* content/events-choice.js —— 多选项·多维度权衡事件（每个 3-5 选项，结果同时牵动多个维度，有得必有失）。全局 helper(add/flag/byClass/bumpMomentum/has/rnd) 直接可用。 */
EVENTS.push(
  // —— 周末怎么过 ——
  { id: "ev_choice_weekend", module: "choice", ambient: true,
    title: "🛋️ 又一个周末，怎么过？",
    text: (s) => "没有闹钟，你却在晨光里自然睁了眼。窗帘缝里漏进一道暖黄，楼下早点摊的吆喝隐隐约约。你赖在床上，伸了个长长的懒腰——这难得的两天，整整四十八小时，全是你的。床头的手机亮着，躺着好几条没读的消息。你盯着天花板，忽然有种握着一把零钱却不知道买什么的甜蜜为难：这个周末，到底该怎么过？",
    choices: [
      { label: "在家躺平补觉，谁也不见", effect: (s) => { add(s, "health", 6); add(s, "stress", -10); add(s, "mood", 3); add(s, "network", -2); return "你把窗帘拉得严严实实，把世界关在门外，一觉睡到日头偏西。醒来时整个人像被重新格式化过，沉甸甸的疲惫泄了洪。你窝在沙发里刷剧到深夜，外卖盒堆了一桌。身体是回了血，可手机里那几个「来不来」的群消息你始终没点开——错过了几场局，有些人的名字，又在你的生活里淡了一截。"; } },
      { label: "约朋友爬山徒步", effect: (s) => { add(s, "body", 2); add(s, "health", 4); add(s, "mood", 6); add(s, "network", 2); add(s, "stress", -4); return "你们一行人天没亮就出发，在山脊上迎着风走了整整一天。越往上爬腿越酸，到后来每一步都在打颤，可视野也跟着一寸寸打开——脚下是云海，远处是连绵的青黛。登顶那一刻谁都没说话，只是大口喘气、大口吹风，憋了许久的浊气仿佛被一并吹散。下山时大家有说有笑，群聊里多了好几张并肩傻笑的合照。汗水冲走了疲惫，也冲淡了平日里的客套。"; } },
      { label: "泡图书馆，给自己充电", effect: (s) => { add(s, "knowledge", 4); add(s, "mind", 1); add(s, "mood", -2); add(s, "stress", 3); return "你拣了图书馆靠窗的位置，把一本厚厚的专业书摊开，一坐就是一整天。阳光在桌面上挪了又挪，你的笔记记了密密麻麻好几页，脑子被填得充实而紧绷。可每当你抬头揉眼睛，窗外草坪上撒欢的人群、嬉笑追逐的孩子，总会冷不丁撞进眼里。那一刻，胸口某处空落落的——你说不清自己是在向前奔跑，还是只是不敢停下。"; } },
      { label: "接个加班的活，多挣点", effect: (s) => { add(s, "cash", 1500); add(s, "stress", 8); add(s, "health", -4); add(s, "mood", -4); return "群里飘来一条「有个急活，谁能接」，你犹豫两秒还是回了「我来」。整个周末你对着电脑赶工，咖啡续了一杯又一杯，腰坐得发僵。周日深夜活儿交了，一笔外快稳稳到账，钱包是鼓了一点。可你瘫在椅子上才惊觉——属于自己的两天，就这么没了。望着窗外漆黑的天，你已经能想象周一早上镜子里那张脸：比周一本身，还要难看。"; } }
    ] },

  // —— 年终奖怎么花 ——
  { id: "ev_choice_bonus", module: "choice", ambient: true,
    cond: (s) => s.cash > 8000,
    title: "🧧 年终奖到账了",
    text: (s) => byClass(s, {
      poor: "手机「叮」地一震，是银行的到账短信。你点开一看，年终奖到了。这是你攒了整整一年的盼头，加班到深夜的那些日子、咽下去的那些委屈，仿佛都浓缩成了屏幕上这一串数字。数字不算大，可在你眼里，每一分都沉甸甸、热乎乎的。你把短信反复看了好几遍——这笔钱，到底怎么花，才对得起这一年？",
      mid: "年终奖落了袋，比你预期的还厚了那么一点点。同事群里早就炸开了锅，有人晒新手机的开箱图，有人甩出三亚的机票截图，配文「奖励一下辛苦的自己」。你靠在椅背上，指尖摩挲着手机，心里盘算开了：这笔钱，是该犒劳自己，还是该攥紧了过日子？",
      rich: "年终奖到账的提示，你扫了一眼就放下了——对你而言，这不过是账面上的一个零头。但日子总要有点仪式感，再不缺钱的人，也得给生活找个由头。你慢悠悠地呷了口茶，饶有兴致地想：这笔无关痛痒的「闲钱」，拿来图个什么乐子好呢？"
    }),
    choices: [
      { label: "全存起来 / 还房贷", effect: (s) => { add(s, "assets", 6000); add(s, "stress", -6); add(s, "mood", -2); return "你一分没舍得动，转手就把它填进了储蓄账户和那个永远填不满的负债窟窿里。看着房贷的本金又少了一点，你长长舒了口气，那根紧绷的弦悄悄松了几分。理智上你知道这是最稳妥的选择。可关掉转账界面的那一刻，原本想着「今年总该犒劳自己一回」的那点小小兴致，也跟着无声地熄了火。"; } },
      { label: "换台新手机 / 数码尝鲜", effect: (s) => { add(s, "cash", -5000); add(s, "mood", 8); add(s, "reputation", 2); return "崭新的设备捧在手里，包装膜还带着工厂的味道。撕开它、按下开机键的那一刻，屏幕亮起，你心里像过年一样雀跃。同事凑过来看，眼里是藏不住的艳羡，「真舍得啊」。你嘴上谦虚着「就图个顺手」，手指却忍不住一遍遍摩挲着光滑的机身——有些快乐很短，但此刻它真真切切。"; } },
      { label: "报个进修班提升自己", effect: (s) => { add(s, "cash", -4000); add(s, "knowledge", 5); add(s, "insight", 2); add(s, "mood", 1); return "你深吸一口气，把这笔奖金一股脑砸进了一门一直想报却舍不得报的课程。付款成功的瞬间，钱包空了，心也跟着抽了一下，肉疼是真肉疼。可当你翻开第一页讲义，看见那些陌生又诱人的知识，那种「我正在变成更好的自己」的踏实感，又一点点漫上心头——这钱，花得值。"; } },
      { label: "带爸妈出去旅游", effect: (s) => { add(s, "cash", -6000); add(s, "mood", 10); add(s, "health", 2); add(s, "reputation", 3); return "你瞒着爸妈悄悄订好了机票，直到出发那天才宣布「带你们去看海」。这是他们这辈子头一回坐飞机，头一回看见真正的大海。海风咸咸的，浪一遍遍扑上沙滩，妈妈卷起裤脚踩进水里，笑得像个没长大的孩子，爸爸举着手机笨拙地给她拍照。你站在一旁看着这一幕，鼻子忽然有点酸——这一刻的圆满，比账户上任何一个数字都值钱。"; } },
      { label: "小赌一把，买点理财/彩票", effect: (s) => { const win = rnd(0.35); if (win) { add(s, "cash", 4000); add(s, "mood", 7); bumpMomentum(s, 4); return "鬼使神差地，你把奖金投进了一个「稳赚」的小标的。本以为是图个刺激，谁知手气竟出奇地好，没几天账户就实打实地涨了一截。你乐得当场在群里发话「这顿奶茶我请了」，全组欢呼。那几天你走路都带风，飘飘然觉得自己八成是天生的偏财命——这，往往是危险的开始。"; } add(s, "cash", -3000); add(s, "mood", -6); bumpMomentum(s, -3); return "你揣着「钱生钱」的美梦把奖金投了进去，结果连个水花都没溅起来。数字一天天往下缩，你刷新了一遍又一遍，最后只能对着惨绿的屏幕苦笑。所谓「让钱替你打工」，到头来你才悟出真相——钱没生钱，倒是生了一肚子气。"; } }
    ] },

  // —— 同事矛盾怎么处理 ——
  { id: "ev_choice_coworker", module: "choice", ambient: true,
    cond: (s) => !!s.job || has(s, "employed"),
    title: "😤 同事抢了你的功劳",
    text: (s) => "周一上午的项目汇报会，会议室的投影亮着。轮到那个方案时，你下意识坐直了身子——那是你连着三个晚上熬到凌晨、改了七八版才磨出来的东西，每一页 PPT 的逻辑你都烂熟于心。可开口的人，是坐在你斜对面的同事。他不疾不徐地讲着，一字一句几乎和你的初稿分毫不差，落款那一栏，赫然印着他的名字。领导听得频频点头，连说了两个「这个思路好」。你缩在会议室的角落，手心攥出了汗，一股热血「腾」地往脑门上涌——这口气，是咽，还是不咽？",
    choices: [
      { label: "当场拆穿，据理力争", effect: (s) => { add(s, "reputation", 4); add(s, "stress", 8); add(s, "mood", 2); add(s, "network", -3); return "你「啪」地合上笔记本站了起来，声音不大却字字带钉。你当着所有人的面调出聊天记录、初稿的创建时间戳、一版版的修改痕迹，证据链一环扣一环。会议室瞬间死寂，那位同事的脸由红转白。你赢了，赢得彻彻底底——可你也清楚，这层皮一旦撕破就再缝不上了。往后和他共事，每一天都像踩在碎玻璃上，处处是刺。"; } },
      { label: "私下找他摊牌", effect: (s) => { add(s, "strategy", 1); add(s, "stress", 3); add(s, "network", -1); return "散会后，你在茶水间堵住了他，压着翻涌的火气，尽量平静地把话挑明。他先是装傻，被你一句句逼到墙角，最后讪讪地低下头道歉，连声保证「下次一定署上你」。事情没闹大，面子都保住了。可你心里清楚，有些东西碎了就是碎了——那点曾经的信任，再也回不到从前。"; } },
      { label: "忍下来，去找领导单聊业绩", effect: (s) => { add(s, "strategy", 2); add(s, "insight", 1); add(s, "mood", -4); add(s, "stress", 5); return "你当场什么都没说，把那口气硬生生压回了胸腔。可转过头，你抓住一个机会单独找到领导，把项目后续的推进、那些只有你最清楚的细节，一条条不动声色地汇报上去，悄悄又把存在感刷了回来。憋屈吗？真憋屈，那一整天你脸都是僵的。可你也想明白了——成年人的战场不看谁嗓门大，只看最后谁站着。"; } },
      { label: "算了，多一事不如少一事", effect: (s) => { add(s, "mood", -8); add(s, "stress", 6); add(s, "reputation", -2); return "你深吸一口气，又一次把翻涌上来的不甘咽了回去，脸上挤出一个「没关系」的表情，假装这事压根没发生过。可沉默从来不是免费的。那位同事见你这般好欺负，往后愈发肆无忌惮，连别人的功劳也敢明目张胆地揽。而你，在一次次的退让里，慢慢活成了办公室里那个谁都记不住名字的透明人。"; } }
    ] },

  // —— 要不要帮朋友 ——
  { id: "ev_choice_lend", module: "choice", ambient: true,
    cond: (s) => s.cash > 12000,
    title: "📱 朋友半夜来借钱",
    text: (s) => "凌晨一点多，手机屏幕在黑暗里亮起，是那个认识了十几年的老朋友。他发来长长一段话，字里行间透着急：生意周转不灵，眼看就要断了链子，急需两万块救命，下个月发了款一定如数奉还。末了还补了句「实在是走投无路才张这个口」。你盯着对话框，输入栏的光标一闪一闪，像在催你表态。借吧，万一是肉包子打狗有去无回；不借吧，多年的交情，怕是这一下就寒透了。你的拇指悬在屏幕上方，迟迟落不下去。",
    choices: [
      { label: "二话不说，全额借出", effect: (s) => { add(s, "cash", -20000); add(s, "network", 4); add(s, "mood", 3); flag(s, "lent_friend"); if (rnd(0.5)) { return "你没多问一句，干脆利落地把两万块转了过去，还附上一句「先应急，不急着还」。对面半天没回，再发来时已是语无伦次的感谢，最后是一句「这辈子记着你」。后来他果然挺了过来，从此你的事就是他的事——这份雪中送炭，他记了一辈子。有些情分，恰恰是在最难的关口才真正长出来的。"; } add(s, "mood", -5); return "你没多想，干脆利落地把两万块转了过去。他千恩万谢，赌咒发誓下月必还。可日子一天天过去，他的消息回得越来越慢，到后来索性石沉大海，朋友圈也对你设了「仅三天可见」。那两万块和那个曾经掏心掏肺的朋友，就这么一起消失在了茫茫人海里。你不是心疼钱，你是想不通——人怎么说变就变。"; } },
      { label: "只借一半，量力而行", effect: (s) => { add(s, "cash", -10000); add(s, "insight", 1); add(s, "network", 1); return "你斟酌再三，转了一万过去，附上一句「我手头也紧，只能帮到这，剩下的你再想想别的辙」。对面沉默了一会儿，回了个「够了够了，谢谢」。你听得出那点失落，关系似乎也淡了那么一丝。可你不后悔——救急不救穷，量力而行，既没让朋友彻底寒心，也守住了自己的底线。成年人的善意，本就该带着分寸。"; } },
      { label: "不借钱，但帮他想办法", effect: (s) => { add(s, "strategy", 2); add(s, "network", 2); add(s, "mood", -2); return "你没掏一分钱，却做了更费心的事。你翻遍通讯录，连夜帮他牵上两个可能搭得上手的人脉，又拨通电话陪他把生意的窟窿一点点捋清，分析哪里能止血、哪里能续命，一直聊到窗外泛白。给钱是把鱼递过去，你却选择陪他学怎么打渔。后来他每每提起，都说那一晚比两万块还顶用——他敬你，敬的是这份真心。"; } },
      { label: "婉拒，钱和感情分开", effect: (s) => { add(s, "mood", -6); add(s, "network", -4); add(s, "stress", 2); return "你斟酌了许久，措辞改了一遍又一遍，最终还是委婉地拒绝了。你跟他说，钱和感情你向来分得清，不是不信他，是怕万一伤了情分。道理你站得住脚，理智上你没做错半分。可发出去之后，那句他没明说、却分明隔着屏幕飘过来的「连这点忙都不肯帮」，还是结结实实地扎了你一下，让你久久没能入睡。"; } }
    ] },

  // —— 健康 vs 事业 ——
  { id: "ev_choice_overtime_health", module: "choice", ambient: true,
    cond: (s) => (s.health || 70) < 75,
    title: "🌙 升职机会与亮起的红灯",
    text: (s) => "公司放出一个晋升名额，规则简单粗暴：谁能扛下这个硬骨头项目，谁就上。消息一出，办公室的空气都绷紧了。你心里清楚这是难得的机会，几年的熬，等的就是这一脚油门。可办公桌抽屉里，还压着上周那张体检报告——几项指标飘着刺眼的红，复查时医生扶了扶眼镜，语气罕见地严肃：「你这个情况，得静养，别再硬撑了。」一边是往上爬的梯子，一边是亮起红灯的身体，这两样，偏偏在此刻狠狠撞在了一起。",
    choices: [
      { label: "拼了！连轴转冲晋升", effect: (s) => { add(s, "reputation", 6); add(s, "strategy", 2); add(s, "health", -10); add(s, "stress", 12); add(s, "mood", -3); if (rnd(0.5)) { add(s, "cash", 20000); return "你把体检报告塞回抽屉，眼一闭心一横，扑了上去。接下来的三个月，你没睡过一个囫囵觉，靠咖啡和意志力续命，硬是把那块硬骨头一点点啃了下来。结果公布那天，你升了职、加了薪。镜子里的人眼窝深陷、面色蜡黄，可工牌上那行新印的头衔，亮得晃眼。值不值，只有夜深人静时你自己知道。"; } return "你把体检报告塞回抽屉，眼一闭心一横，扑了上去。你拼到嗓子里都泛着血腥味，可项目还是因为一个谁也料不到的变故，黄了。竹篮打水一场空——健康赔进去了，位子也没影了。你瘫在工位上，盯着空荡荡的办公室，第一次觉得这么累，累到连叹气的力气都没有。"; } },
      { label: "悠着点，把健康放第一", effect: (s) => { add(s, "health", 8); add(s, "stress", -8); add(s, "mood", 4); add(s, "reputation", -3); return "你想了一整夜，最终还是婉拒了这个名额。从那天起，你逼自己按时吃饭、准点下班、规律锻炼，把那张飘红的报告单贴在了冰箱上提醒自己。一个月后，复查的几项指标悄悄回落，身体一天天轻快起来。只是偶尔，看见接了项目的同事在群里被领导点名表扬、一步步往上走，你心里那根弦，还是会不受控地泛起一丝说不清的不甘。"; } },
      { label: "接下来，但学会甩锅分工", effect: (s) => { add(s, "strategy", 3); add(s, "charm", 1); add(s, "reputation", 2); add(s, "stress", 4); add(s, "health", -3); return "你接了，但这回学聪明了。你没像从前那样把所有担子往自己肩上扛，而是花了半天时间拆解任务、物色帮手，把活儿合理地摊派下去，自己只攥住最关键的那几环。项目照样推进，你却没被掏空。某个加班的深夜，你忽然想通一个道理：职场从来不是比谁更能熬命，而是比谁更会借力。能调动别人，才是真本事。"; } },
      { label: "干脆请长假，彻底调养", effect: (s) => { add(s, "health", 14); add(s, "stress", -14); add(s, "cash", -5000); add(s, "reputation", -5); flag(s, "took_sickleave"); return "你做了个所有人都意外的决定：递了一份长假申请，关掉工作群，去了一处安静的地方彻底调养。每天晒太阳、散步、好好吃饭睡觉，那些被工作绷断的神经一根根松了下来，气色肉眼可见地红润起来，整个人像被重新擦亮。可当你养好身子回到公司，工位还在，事却早已物是人非——晋升的尘埃落了定，曾经熟悉的项目换了人马，你像个迟到的客人，站在了曾经的主场之外。"; } }
    ] },

  // —— 一笔意外之财 ——
  { id: "ev_choice_windfall", module: "choice", ambient: true,
    title: "💰 捡到一个鼓鼓的钱包",
    text: (s) => "下班路上，你照例抄近道穿过那个小公园。天色擦黑，路灯刚亮，你随手扶了下长椅想歇口气，指尖却碰到一个软软的东西——一个钱包，卡在椅板的缝隙里。你捏出来翻开，里头厚厚一沓现金露出毛边，还夹着身份证、好几张银行卡。你下意识地环顾四周：空无一人，连个遛弯的影子都没有，头顶那盏路灯歪着，监控的方向恰好照不到这个角落。世界仿佛只剩你和这个钱包。你的心跳，悄悄快了一拍。",
    choices: [
      { label: "原地等失主 / 交给警察", effect: (s) => { add(s, "reputation", 5); add(s, "mood", 4); add(s, "stress", 2); add(s, "cash", -100); return "你把钱包攥在手里，在那张长椅上一坐就是一个多小时。晚风越吹越凉，你裹紧外套也没挪窝，就等那个一定会回来找的人。天彻底黑透时，一个急匆匆的身影循着记忆跑回来，看见钱包失而复得，激动得话都说不利索，连声道谢。回家的路上你饿得肚子直叫，路边的小吃摊飘着香味你也没停，可心里那杆秤，稳稳当当，比吃饱了还踏实。"; } },
      { label: "拿走现金，钱包丢回去", effect: (s) => { add(s, "cash", 3000); add(s, "reputation", -4); add(s, "mood", -5); flag(s, "petty_theft"); return "你犹豫了几秒，手却比脑子快——抽出那沓现金塞进自己口袋，把瘪下去的空钱包重新卡回了椅缝，仿佛这样就能假装什么都没发生。一路上你走得飞快，不敢回头。回到家数钱时，你才发现自己的手在抖。那几张钞票揣在兜里，烫得人坐立难安，那一夜，你翻来覆去，怎么也睡不着。"; } },
      { label: "全部据为己有", effect: (s) => { add(s, "cash", 5000); add(s, "reputation", -8); add(s, "mood", -8); add(s, "stress", 6); flag(s, "petty_theft"); return "你深吸一口气，把整个钱包连同身份证、银行卡一并揣进了怀里，低着头快步离开了公园。钱是实打实地到手了，足够你松快好一阵。可代价是，往后好长一段日子里，每当你路过小区公告栏、看见街边电线杆上贴着的「寻物启事」，你都会心头一紧，下意识地别开眼，不敢多看一秒。"; } },
      { label: "发个朋友圈帮找失主", effect: (s) => { add(s, "reputation", 3); add(s, "network", 2); add(s, "charm", 1); return "你灵机一动，把钱包外观拍了张照（证件号码细心地打了码），配上「在XX公园捡到钱包，失主请联系我」发了朋友圈，又顺手转进了几个本地群。没想到现在的网络这么神，不到半天，七拐八绕地就真联系上了失主。一来一回间，不少原本不熟的人也记住了你的热心肠，那条动态点赞破了百。举手之劳，温暖了别人，也照亮了自己。"; } }
    ] },

  // —— 被领导穿小鞋 ——
  { id: "ev_choice_scapegoat", module: "choice", ambient: true,
    cond: (s) => !!s.job || has(s, "employed"),
    title: "🎯 锅，从天而降",
    text: (s) => "项目终究还是出了岔子。复盘大会上气氛凝重，所有人都在等一个交代。明明那个关键节点是领导一意孤行、拍脑袋拍出来的决策，可他清了清嗓子，话锋一转，把责任一股脑甩到了你头上：「这块主要是执行层面没跟上。」会议室里几十双眼睛「唰」地一下全聚到你身上，有探究、有同情、也有看热闹的。你能感觉到脸上火辣辣地烧起来，血直往太阳穴里冲——这口从天而降的黑锅，背，还是不背？",
    choices: [
      { label: "硬刚，当众甩出证据链", effect: (s) => { add(s, "reputation", 3); add(s, "stress", 10); add(s, "network", -5); add(s, "mood", 1); return "你压住声音里的颤，不卑不亢地打开电脑，把当初那封拍板的邮件、那份白纸黑字的会议纪要，一条条投到了大屏幕上。「这是当时的决策记录。」短短一句，把皮球稳稳踢了回去。真相大白，全场鸦雀无声，领导的脸青一阵白一阵。你赢了清白，可你也心知肚明——你把顶头上司当众扫了面子，从今往后，这日子，难了。"; } },
      { label: "忍气背锅，暗中留好证据", effect: (s) => { add(s, "strategy", 3); add(s, "insight", 1); add(s, "mood", -7); add(s, "stress", 8); return "你当着所有人的面，硬生生把那口血咽了下去，低声说了句「是我考虑不周」，认下了这口锅。会一散，你回到工位，却悄悄把所有的邮件、聊天记录、版本文档逐一备份、归档、加密。委屈是真委屈，那一整天你嘴里都是苦的。可你也信一句老话——留得青山在，不怕没柴烧。账，先记着；秋后，总有算的那一天。"; } },
      { label: "找更高层的领导申诉", effect: (s) => { add(s, "strategy", 1); add(s, "stress", 6); if (rnd(0.45)) { add(s, "reputation", 5); add(s, "network", 3); return "你赌上一把，绕过直属上司，把事情原原本本捅到了更高层那里。运气站在了你这边——你撞上的是一位真讲道理的大领导，他不动声色地把前因后果查了个底朝天。真相浮出水面，你不仅洗清了冤屈，那份有理有据、临危不乱的劲儿，反倒入了他的眼。这步险棋，你走对了。"; } add(s, "reputation", -6); add(s, "network", -6); return "你赌上一把，绕过直属上司去更高层申诉，结果赌输了。在那位高层眼里，你成了「不懂规矩、越级告状、坏了团队和气」的刺头。他打着哈哈和稀泥，把事情压了下去；你的直属领导则把这笔账牢牢记在了心上。里外不是人——你两头都没讨着好。"; } },
      { label: "心灰意冷，默默更新简历", effect: (s) => { add(s, "mood", -4); add(s, "stress", -3); add(s, "insight", 2); flag(s, "job_hunting"); return "你没争，没吵，也没辩。散会后你平静地回到工位，连表情都没什么变化，只是趁着午休，悄悄打开了那个许久没碰的招聘软件，开始一份份地刷新简历、投递职位。你忽然觉得心里轻松了——这家庙既然容不下你这尊佛，那就趁早换个码头。从认下这口锅的那一刻起，你的心，其实就已经不在这里了。"; } }
    ] },

  // —— 家庭与工作冲突 ——
  { id: "ev_choice_family_work", module: "choice", ambient: true,
    cond: (s) => has(s, "married") || has(s, "has_kid") || has(s, "partner"),
    title: "📞 加班通知 vs 家庭约定",
    text: (s) => "今晚是个早就圈在日历上的日子——你答应了家人，雷打不动要回去的那种。你甚至连礼物都备好了，藏在抽屉里。可偏偏就在下班前最后十分钟，领导端着保温杯踱到你工位旁，一句话不带商量：「有个紧急项目，今晚得留下加班。」你的手机几乎同时震了一下，是家里发来的消息，附了张布置好的照片，配文「就等你了」。一边是屏幕里满满的期待，一边是头顶沉甸甸的压力，两头的分量你都掂得清清楚楚——这一刻，你怎么选？",
    choices: [
      { label: "推掉加班，回家陪家人", effect: (s) => { add(s, "mood", 8); add(s, "health", 2); add(s, "reputation", -4); add(s, "stress", 3); return "你深吸一口气，硬着头皮走到领导面前，第一次把「这个我今晚真的不行」说出了口。说完手心全是汗。你几乎是冲下楼、一路小跑赶回家，推门进去时，正好赶上最热闹的那一刻。家人转过头来，笑靥如花，「可算回来了！」那顿饭你吃得格外香，香得眼眶都有点热。代价嘛——领导那张拉长的脸，还有明天办公室里那点微妙的气氛，就留给明天的自己去面对吧。"; } },
      { label: "留下加班，先把工作扛了", effect: (s) => { add(s, "reputation", 4); add(s, "cash", 800); add(s, "mood", -8); add(s, "stress", 6); return "你给家里发了条长长的道歉，每个字都写得心虚，然后默默留了下来，对着电脑苦战到深夜。办公室一盏盏灯熄灭，最后只剩你这一片光。项目稳住了，领导临走前拍了拍你肩膀说「靠谱」。可深夜回放家人发来的视频时，孩子那句奶声奶气的「爸爸/妈妈怎么又不回来」，还有那双瞬间黯淡下去的眼睛，像根细刺扎进心里，让你一整晚翻来覆去，怎么也缓不过来。"; } },
      { label: "加急赶完核心部分，提前溜", effect: (s) => { add(s, "strategy", 2); add(s, "stress", 8); add(s, "mood", 3); add(s, "health", -2); return "你脑子飞速运转，当机立断：先挑最要命的核心部分死磕。接下来的两个小时你进入了某种疯魔状态，手速飞快，硬是把别人要熬一晚上的活儿压缩着干完，质量还不打折。临走撂下一句「剩下的边角料明早一早搞定」，便抓起外套夺门而出。冲进夜色里那一刻你浑身脱力、太阳穴突突直跳，可嘴角是扬着的——这一回，工作没塌，家也没塌，两头你都接住了。"; } },
      { label: "带着电脑回家，两头兼顾", effect: (s) => { add(s, "mood", -2); add(s, "stress", 10); add(s, "health", -3); add(s, "reputation", 1); return "你想了个「两全」的法子，抱起笔记本就往家赶，盘算着边陪家人边把活儿干了。可现实很快给了你一巴掌：你陪家人说话时心里惦记着没回的工作消息，敲键盘时家人又在旁边欲言又止。一晚上下来，陪是陪了，活也干了，可哪一样都做得潦草、做得心不在焉。深夜合上电脑，你揉着发胀的太阳穴才惊觉——人哪有什么分身术，所谓兼顾，不过是两边都辜负。"; } }
    ] },

  // —— 学习新技能选哪个方向 ——
  { id: "ev_choice_skill", module: "choice", ambient: true,
    title: "📚 想学点东西，往哪个方向钻？",
    text: (s) => "年初一个安静的夜里，你给自己泡了杯茶，翻开一个崭新的笔记本，郑重写下「今年要变得更厉害一点」。可笔尖悬在纸上，你又犯了难——一天就那么二十四小时，下了班剩的精力屈指可数，贪多嚼不烂，真要钻，也只能押一个方向。摊在你面前的有好几条路，每一条都闪着诱人的光，每一条又都要你拿真金白银的时间去填。深吸一口气，你问自己：这一年，赌哪个？",
    choices: [
      { label: "硬核技术 / 编程", effect: (s) => { add(s, "knowledge", 5); add(s, "mind", 2); add(s, "stress", 5); add(s, "health", -2); add(s, "mood", -2); return "你一头扎进了一门硬邦邦的技术，对着满屏看不懂的文档和报错，一行行地啃。无数个夜晚你抓着头发对着屏幕发呆，进度慢得让人想砸键盘，挫败感一波接一波。可每当你死磕到凌晨、终于让那段卡了三天的东西跑通的瞬间，那种成就感又会瞬间把疲惫冲散。你心里清楚，这条路最苦，但每攻克一个难点，你脚下的「护城河」就深一分——深到别人轻易跨不过来。"; } },
      { label: "口才 / 演讲表达", effect: (s) => { add(s, "charm", 4); add(s, "network", 2); add(s, "mood", 2); return "你逼自己开口。对着镜子练表情、掐着秒表改逐字稿，把每一次发言都当成一场小型作战。一开始你紧张得舌头打结、手心冒汗，可练得多了，那层壳一点点磨掉了。慢慢地，会议上你越来越敢举手，话也越说越有条理、有底气。你开始真切地体会到一个残酷又现实的道理：很多时候，机会未必落在做得最好的人头上，而是落在最会把事情说明白、说漂亮的那个人手里。"; } },
      { label: "理财 / 投资认知", effect: (s) => { add(s, "insight", 4); add(s, "strategy", 2); add(s, "stress", 2); return "你系统地补起了财商这门从没人教过你的课，从最基础的概念啃到资产配置的逻辑。神奇的是，学着学着，你看世界的角度都变了——同样一条新闻，过去你一扫而过，现在却能咂摸出背后钱的流向。短期内，这门功课看不出半点名堂，账户也没多一分钱。但你隐隐觉得，这双逐渐「看得懂钱」的眼睛，是会随着时间慢慢升值的，迟早有一天，它会替你赚回远不止这点学费。"; } },
      { label: "身体管理 / 一门运动", effect: (s) => { add(s, "body", 3); add(s, "health", 6); add(s, "stress", -6); add(s, "mood", 4); return "你把今年的赌注，押在了自己的身体上，认认真真练起了一项运动。从一开始气喘吁吁、第二天浑身酸痛得下不了床，到后来动作越来越标准、耐力越来越扛造。书本上的学识是没怎么长，可镜子里的人精气神肉眼可见地不一样了：腰板挺了，眼睛亮了，连熬夜后的恢复都快了。你这才明白，身体才是那个「1」——扛事的本钱厚实了，后面的那些「0」才有意义。"; } },
      { label: "啥也不学，先把觉睡饱", effect: (s) => { add(s, "health", 4); add(s, "stress", -5); add(s, "mood", 2); add(s, "knowledge", -1); return "想了半天，你把那个雄心勃勃的计划合上，给「上进」这件事按下了暂停键。你太累了，累到一想到「学习」两个字就犯困。于是这段日子你只做一件事：好好休息，睡到自然醒，把这些年欠下的觉一点点补回来。身体确实舒坦了不少。只是夜深刷手机时，看见朋友圈里别人晒证书、晒打卡、晒进步，你心里那点焦虑，还是没能彻底散干净——休息和懈怠的边界，有时候很模糊。"; } }
    ] },

  // —— 社交局怎么应对 ——
  { id: "ev_choice_party", module: "choice", ambient: true,
    title: "🍷 一场没法推的饭局",
    text: (s) => "你被半推半就地拉进了一个饭局，推脱不掉。包间里灯光昏黄，一张大圆桌坐满了人，个个都是平日里你想见都见不着、能说得上话的人物。空气里飘着酒气和客套，敬酒声、寒暄声、名片来回递的声音此起彼伏。你端着杯子，浑身不自在，像个误入正剧片场的群演。可你也心里有数——这年头，多少机会、多少门路，恰恰就藏在这觥筹交错、半醉半醒的推杯换盏里。这一场，你打算怎么混？",
    choices: [
      { label: "豁出去，主动敬酒攒人脉", effect: (s) => { add(s, "network", 5); add(s, "charm", 1); add(s, "health", -5); add(s, "cash", -800); add(s, "stress", 4); return "你一咬牙，端起杯子站了起来，从桌头敬到桌尾，「久仰久仰」「以后多关照」说得一套一套。酒过三巡，你喝得脸红脖子粗，舌头都开始打飘，但微信加了一圈，名片塞满了口袋。第二天一早，宿醉的脑袋疼得像要裂开，你扶着墙去倒水。可打开通讯录，那几个关键的名字静静躺在那里——你知道，这场罪没白受。"; } },
      { label: "找个角落安静观察", effect: (s) => { add(s, "insight", 3); add(s, "mind", 1); add(s, "network", -1); return "你不动声色地挑了个不起眼的位置坐下，话不多，酒也只是浅尝，更多时候只是端着杯子静静地看。看谁在捧谁、谁在不动声色地踩谁，看一句玩笑话背后藏着怎样的机锋，看权力和人情如何在这张桌子上悄悄流动。一场酒局下来，你没攒下几个联系人，却像读了一本活生生的人情世故教科书，那些门道，你又参透了几分。"; } },
      { label: "只和真正聊得来的人深聊", effect: (s) => { add(s, "network", 2); add(s, "charm", 2); add(s, "mood", 3); return "你懒得参与那些客套的循环，索性避开了满场的无效寒暄，找到一两个眼神里有真东西、话能聊到一块去的人，挪到角落里促膝长谈。从工作聊到理想，从困惑聊到生活，越聊越投机，连酒都忘了喝。散场时你认识的人没几个，但交下的那一两个，是日后真能掏心窝子、能搭把手的朋友。你向来信：交情这事，质量远胜数量。"; } },
      { label: "借口溜了，回家清静", effect: (s) => { add(s, "health", 3); add(s, "mood", 4); add(s, "stress", -4); add(s, "network", -3); return "实在受不了那股窒息的热闹，你趁着上厕所的空当，编了个「家里有点急事」的由头，提前抽身溜了。回到家，你换上睡衣，给自己泡了杯热茶，窝进沙发里，整个世界瞬间安静下来，身心都舒坦了。只是夜深了，你偶尔也会想起那一桌人——你错过的那些「机会」，究竟是不是真的机会，恐怕永远没人能给你答案了。"; } }
    ] },

  // —— 面对诱惑 ——
  { id: "ev_choice_temptation", module: "choice", ambient: true,
    cond: (s) => (s.stats && s.stats.strategy >= 0),
    title: "💼 一笔来路不明的「快钱」",
    text: (s) => "一个许久没联系的老熟人忽然约你喝茶，落座没几句，他就压低了声音，神秘兮兮地凑过来：「跟你说个门路，躺着就能数钱的那种。」他给你比划着一串数字，回报高得离谱，离谱到不真实——「就是吧，稍微游走在灰色地带，但你放心，绝对安全，出不了事，我都做半年了。」他拍着胸脯打包票，眼睛却亮得有点过头。你端着茶杯没说话，可心里那根弦，已经被那串撩人的数字拨动了一下。",
    choices: [
      { label: "断然拒绝，钱要赚得干净", effect: (s) => { add(s, "reputation", 3); add(s, "insight", 2); add(s, "mood", -2); return "你放下茶杯，客气却没有半分商量余地地回绝了：「这钱我赚不了，心里过不去。」对方脸上的热情肉眼可见地凉了下去，悻悻地起身告辞。说不动心是假的——往后某些深夜，你也会冒出「万一那真行呢」的念头。但你更清楚一件事：再多的钱，也换不来一个能踏踏实实睡着的觉。这账，你算得明白。"; } },
      { label: "小试一把，浅尝即止", effect: (s) => { add(s, "stress", 6); if (rnd(0.5)) { add(s, "cash", 8000); add(s, "mood", 4); bumpMomentum(s, 3); return "你抱着「试试水、见好就收」的心思投了一小笔，权当交个学费。没想到没过几天，钱真就实打实地到了账，数目还不小。你盯着那个增长的数字，心跳得有点快——钱来得太轻松了，轻松到你脑子里那个危险的念头开始冒头：要不……再多投一点？欲望的口子，往往就是这样被撕开的。"; } add(s, "cash", -5000); add(s, "mood", -8); add(s, "reputation", -3); bumpMomentum(s, -4); return "你抱着「就试一点，亏了也不肉疼」的心思投了笔本金，结果连个回响都没有。再去找那个老熟人，电话不接、消息不回，人间蒸发。你这才咂摸过味来：他口口声声的「绝对安全」，安全的从头到尾只有他一个人。这笔学费，买来一个早该懂的道理。"; } },
      { label: "梭哈！富贵险中求", effect: (s) => { add(s, "stress", 14); if (rnd(0.3)) { add(s, "cash", 40000); add(s, "mood", 8); add(s, "reputation", -2); bumpMomentum(s, 6); return "你一咬牙，把能动用的钱几乎全押了上去——富贵险中求嘛。结果命运跟你开了个「好」玩笑：你竟真的一夜暴富，账户数字翻了好几番，看得人头晕目眩。可怪就怪在，这钱赚得越多，你睡得越不安稳。半夜里楼道一点响动、门铃偶尔一响，你都会「腾」地从床上弹起来，心脏狂跳。原来昧着良心赚的钱，是要拿安宁去抵押的。"; } add(s, "cash", -15000); add(s, "reputation", -10); add(s, "mood", -12); flag(s, "got_scammed"); bumpMomentum(s, -8); return "你眼一闭心一横，把家底重仓押了上去。然后，你眼睁睁看着那笔钱连本带利被卷得一干二净，对方拉黑了你、注销了账号，消失得彻彻底底。最讽刺的是，因为这事本身就见不得光，你连报警都开不了口，只能把满嘴的血和悔，硬生生往肚子里咽。这一课，学费贵得让你刻骨铭心。"; } },
      { label: "假意答应，暗中收集证据举报", effect: (s) => { add(s, "strategy", 3); add(s, "insight", 2); add(s, "reputation", 5); add(s, "stress", 8); return "你不动声色地笑了笑，假意应承下来，顺着他的话头一点点往深里套。聊天记录、转账凭证、上线的信息……你不动声色地一样样攒齐，然后把这一整套料，原原本本递到了该去的地方。事了，你既守住了自己的底线，又落了个「嫉恶如仇、敢做敢当」的名声。只是配合调查的那几天，你白天强作镇定、夜里辗转难眠，那种提着心吊着胆的滋味，真不好受。"; } }
    ] },

  // —— 道德两难 ——
  { id: "ev_choice_moral", module: "choice", ambient: true,
    title: "⚖️ 你撞见了不该看见的事",
    text: (s) => "一个普通的加班夜，你回工位拿落下的钥匙，却撞见了不该撞见的一幕——关系一向不错的那位同事，正对着电脑做假账，数字改得心惊肉跳，金额绝不是小数目。你们的目光在空荡的办公室里撞上，他脸色「唰」地白了。第二天，他堵住你，赔着笑脸求你睁一只眼闭一只眼，临走还硬塞给你一个鼓囊囊的红包。你捏着那个红包，只觉得烫手。检举，是亲手把朋友送进去；沉默，是把自己也拖下水。这道题，没有不疼的答案——你怎么办？",
    choices: [
      { label: "实名检举，公事公办", effect: (s) => { add(s, "reputation", 6); add(s, "stress", 10); add(s, "network", -6); add(s, "mood", -3); return "你纠结了好几个不眠之夜，最终还是把那个红包原封退了回去，转身把证据一五一十地递到了该去的地方。公司的窟窿堵住了，账目查清了，可那位同事锒铛入局，从此办公室里看你的眼神都变了——没人再敢跟你走得太近，连寒暄都带着戒备。你做了对的事，却也尝到了对的事的代价：正义的尽头，常常是孤独。"; } },
      { label: "私下逼他收手，给条退路", effect: (s) => { add(s, "strategy", 2); add(s, "insight", 2); add(s, "stress", 6); add(s, "network", 1); return "你把红包推了回去，没声张，而是把他拉到没人的角落，把话说得又狠又透：「窟窿趁早补上，钱一分不少地填回去，否则别怪我。」你给了他一条退路，也给了他一记重锤。他听得冷汗直冒，连连点头，千恩万谢地照做了。你既没亲手毁掉一个人，也没让自己沾上半点泥。有时候，最难的不是举报或沉默，而是在两者之间，找到那条让人重新做人的窄路。"; } },
      { label: "收下红包，当作没看见", effect: (s) => { add(s, "cash", 5000); add(s, "reputation", -6); add(s, "mood", -10); add(s, "stress", 8); flag(s, "covered_fraud"); return "你犹豫了几秒，到底还是把那个红包揣进了兜里，对自己说「不关我事，何必当恶人」。可从揣下它的那一刻起，你和他就成了一根绳上的蚂蚱。他看你的眼神里多了一层心照不宣的「默契」，而你，时时刻刻活在「万一哪天东窗事发」的阴影里。把柄攥在别人手里的滋味，那种半夜惊醒、心头发慌的难受，比那几张钞票带来的快意，难受了一百倍。"; } },
      { label: "假装从没发生，远远躲开", effect: (s) => { add(s, "mood", -5); add(s, "stress", 5); add(s, "insight", 1); return "你既没收那个红包，也没去举报，只是默默把它退了回去，然后从此装聋作哑，能离他多远就离多远，连一起吃饭都开始找借口推。你以为这样就能把自己摘干净，明哲保身。可你心里也清楚，纸终究包不住火——真到东窗事发那天，「你早就知道却一声不吭」这条，你未必就能真的撇得清。骑墙的人，往往两头都落不着好。"; } }
    ] },

  // —— 时间分配两难 ——
  { id: "ev_choice_time", module: "choice", ambient: true,
    title: "⏳ 一天就这么点时间",
    text: (s) => "这阵子你忙得脚不沾地，像个上了发条停不下来的陀螺。工作、健康、感情、自我提升——四只球同时在空中飞，可你心里清楚，凭你这点精力，撑死也就接得住一两个，剩下的，只能眼睁睁看它们落地。下班的铃声响了，你瘫在椅子上，望着窗外暗下来的天，盘算着这宝贵的几个钟头：今晚，你优先砸给谁？",
    choices: [
      { label: "继续卷工作，把活干漂亮", effect: (s) => { add(s, "reputation", 4); add(s, "cash", 600); add(s, "health", -4); add(s, "mood", -3); add(s, "stress", 6); return "你揉了揉太阳穴，又一次把时间整个儿喂给了工作。你把手头的活儿打磨得无可挑剔，产出亮眼，领导在群里发了个赞。可代价是，身体在隐隐抗议，朋友的消息你回了句「改天」，那本想读的书又在床头落了灰。你成了同事口中那个让人佩服又怕被比下去的「卷王」，也成了自己眼里那个转个不停、却越转越晕的陀螺。"; } },
      { label: "去运动健身，给身体回血", effect: (s) => { add(s, "body", 2); add(s, "health", 6); add(s, "stress", -8); add(s, "mood", 4); return "你一咬牙，把没回完的消息扣在桌上，换上运动鞋出了门。跑道上风迎面吹来，你越跑越畅快，一身大汗淋漓而下，那些在脑子里盘旋了一天的烦心事，竟也跟着汗水蒸发了大半。运动结束，你大口喘着气，整个人神清气爽，紧绷了一天的弦终于松了下来。工作的事？明天那个精力满格的你，一定会感谢今天舍得给身体回血的自己。"; } },
      { label: "陪伴重要的人 / 维系感情", effect: (s) => { add(s, "mood", 7); add(s, "network", 2); add(s, "charm", 1); add(s, "stress", -3); return "你把手机调成了静音，把这几个钟头，整整齐齐地留给了那个在你心里最重要的人。没有谈正事，没有刷手机，只是认认真真地听对方说话，用心地陪着。这样的投入看不见任何KPI、换不来任何回报，可你知道，正是这些不计回报的时光，才是你在兵荒马乱的日子里，最稳、最沉的那块压舱石。船开得再快，也得有它压着，才不会翻。"; } },
      { label: "独处充电，读书 / 复盘", effect: (s) => { add(s, "knowledge", 3); add(s, "insight", 2); add(s, "mind", 1); add(s, "mood", 1); return "你轻轻关上门，把喧嚣和催促都隔在了外面，给自己留出一块谁也打扰不到的清静地。台灯下，你翻开搁置许久的书，又摊开本子，把这阵子的得失冷静地复了个盘——哪步走对了，哪步该改。这种成长安安静静，没人看得见，朋友圈也发不出什么动静。可你隐隐知道，恰恰是这些无声的积累，会在某个不经意的时刻，悄悄拉开你和别人的差距。"; } }
    ] },

  // —— 投资风格选择 ——
  { id: "ev_choice_invest_style", module: "choice", ambient: true,
    cond: (s) => s.cash > 20000,
    title: "📈 这笔闲钱，怎么打理？",
    text: (s) => `深夜，你打开手机银行，盯着账户里那笔闲钱——约 ¥${Math.round(s.cash).toLocaleString()}。它就那么静静躺着，不痛不痒，可你心里清楚，通货膨胀是头不眠的野兽，钱搁着不动，每天都在悄悄缩水。想拿去投，又怕一脚踩进雷区，连本带利打了水漂。手指在屏幕上方悬了半天，你反复盘算着：这笔钱，到底该用哪种打法，才睡得着、又不亏？`,
    choices: [
      { label: "稳健派：存银行 / 买国债", effect: (s) => { add(s, "assets", Math.round(s.cash * 0.15)); add(s, "stress", -4); add(s, "insight", 1); return "你想了想，还是选了最稳妥的那条路，把钱挪进了银行定存和国债这类低风险的篮子里。收益薄得像层纸，一年下来也涨不了多少，旁人或许会笑你太保守。可你不在乎——夜里你睡得踏踏实实，从不必为屏幕上跳动的红绿提心吊胆。在一个人人都想暴富的年代，「稳稳地不亏」，本身就是一种难得的赢。"; } },
      { label: "均衡派：基金定投", effect: (s) => { add(s, "strategy", 1); add(s, "insight", 2); if (rnd(0.55)) { add(s, "assets", Math.round(s.cash * 0.2)); add(s, "mood", 3); return "你设好了每月自动定投，从此不再天天盯盘，涨了不狂喜，跌了也不慌着割肉。账户像爬楼梯一样，一阶一阶、不紧不慢地往上走。回头看，你才发现正是这份「钝感力」帮了你大忙——市场一惊一乍的那些日子里，多少人被吓得追涨杀跌、来回挨刀，而你稳如老狗，悄悄躲过了一次又一次。"; } add(s, "assets", -Math.round(s.cash * 0.05)); return "你照计划坚持定投，偏偏赶上市场一段剧烈震荡，账户短期浮亏，绿油油一片。你死死按住了那只想点「卖出」的手，一遍遍告诉自己「长期持有、别被情绪牵着走」。道理你都懂，可账户连着飘绿的那几周，每次打开都像被针扎一下，心里直打鼓，夜里也忍不住翻看好几遍。考验人性的，从来不是上涨，是下跌。"; } },
      { label: "激进派：重仓股票 / 加密", effect: (s) => { add(s, "stress", 8); if (rnd(0.4)) { add(s, "cash", Math.round(s.cash * 0.6)); add(s, "mood", 8); bumpMomentum(s, 5); return "你心一横，重仓杀了进去，把宝押在了一个看好的方向上。这一回，运气和节奏都站在你这边——账户一路飘红，曲线陡得吓人，短短几个月赚的，顶别人辛辛苦苦攒好几年。你看着翻倍的数字，飘飘然地觉得自己大概是天生吃这碗饭的料。可你不知道，这种「我天赋异禀」的错觉，往往正是亏掉一切的开始。"; } add(s, "cash", -Math.round(s.cash * 0.4)); add(s, "mood", -10); bumpMomentum(s, -5); return "你满仓杀入，自以为踩准了风口，结果却精准地买在了山顶。第二天起，曲线就开始头也不回地往下坠，一波回调下来，你的本金直接腰斩。你盯着满屏惨绿的数字，手指冰凉，反复刷新也改变不了现实。那一刻，你第一次真真切切地、用真金白银的痛，懂了什么叫「韭菜」。"; } },
      { label: "投资自己：拿去进修 / 创业", effect: (s) => { add(s, "cash", -Math.round(s.cash * 0.3)); add(s, "knowledge", 4); add(s, "insight", 3); add(s, "strategy", 2); return "你做了个旁人看不太懂的决定：钱没投进任何一个市场，而是一股脑砸向了自己——报了门一直想学的课，去结识了几个圈内的人，还试着捣鼓起一个不大不小的项目。账面上，这笔钱短期内只见出不见进，纯亏。可你赌的是更长的牌局——投在自己脑子里、本事上、视野里的钱，从来不会贬值，它的复利，悄悄藏在往后漫长的岁月里，会在某一天连本带利地还给你。"; } }
    ] },

  // —— 生活方式选择 ——
  { id: "ev_choice_lifestyle", module: "choice", ambient: true,
    title: "🏙️ 大城市的去与留",
    text: (s) => byClass(s, {
      poor: "又是一个加班到深夜的晚上。你挤在末班地铁里，被人潮推搡着，玻璃窗映出你疲惫的脸，背后是这座城市无边无际、璀璨夺目的灯火。可你忽然发觉，这万家灯火里，没有一盏是为你而亮的。你扶着栏杆，第无数次问自己同一个问题：是在这座繁华却不属于你的城市里继续死磕，还是收拾行李回老家，求一份触手可及的安稳？这道题，从来就没有标准答案。",
      mid: "房贷压着、通勤耗着、内卷裹挟着……这座城市的繁华是真繁华，可身上的疲惫也是真疲惫。这天下班，你没急着回家，独自站在天桥上，看脚下川流不息的车灯连成一条发光的河。你点了支烟，或是只是静静地站着，心里反复琢磨着同一件事：眼下这日子，是咬着牙继续这么过下去，还是干脆换一种活法？",
      rich: "对你来说，留在哪儿、去哪儿，早已不是生存问题——天南海北，你都有底气把日子过得舒坦。于是这道困住无数人的难题，到了你这儿，便简化成了一道纯粹的偏好题：是想要都市的繁华热闹、车水马龙，还是向往山高水长、岁月静好？无非看你此刻的心，更想要哪一种风景罢了。"
    }),
    choices: [
      { label: "留下死磕，赌一个未来", effect: (s) => { add(s, "stress", 8); add(s, "strategy", 2); add(s, "network", 3); add(s, "health", -3); add(s, "mood", -2); flag(s, "stay_bigcity"); return "你最终还是咬了咬牙，把回家的念头摁了下去，决定留下来，继续在这条机会与压力齐头并进的洪流里搏命冲浪。这里的天花板高得望不到顶，可这里的疲惫也深得见不着底。你心里清楚自己在赌什么——你赌的是熬过眼前这段最难的日子，换来后半生一个翻盘的可能。这一注，押的是青春，也是希望。"; } },
      { label: "回老家，求一份安稳", effect: (s) => { add(s, "health", 8); add(s, "stress", -12); add(s, "mood", 5); add(s, "network", -5); add(s, "cash", -3000); flag(s, "hometown"); return "你终于卷起铺盖，告别了那座待了多年的大城市，回到了生你养你的小城。日子一下子慢了下来：清晨能听见鸟叫，街坊邻里见面会笑着打招呼，父母就在身边，压力像潮水一样退去。你睡得安稳，吃得也香。只是偶尔，夜深人静时，那点没来得及实现的雄心，还是会在心底毫无预兆地「咯噔」一下，提醒你曾经也想过要去远方。"; } },
      { label: "去新一线 / 二线折中", effect: (s) => { add(s, "mood", 3); add(s, "stress", -4); add(s, "insight", 2); add(s, "network", -2); add(s, "cash", -2000); return "你没走极端，而是挑了座折中的城市——一座生活成本和机会都打了点折扣的新一线。这里没有一线那么挤、那么逼人，也没有老家那么闲、那么甘于平淡。房价咬咬牙够得着，工作也还有奔头。它给不了你一步登天的传奇，却实实在在地，给疲于奔命的你，留出了一道喘息的缝隙。进可攻，退可守，你想要的，本就是这份从容。"; } },
      { label: "搞副业攒钱，伺机数字游民", effect: (s) => { add(s, "knowledge", 2); add(s, "insight", 2); add(s, "stress", 5); add(s, "health", -2); flag(s, "freelance_dream"); return "你给自己定了个更野的目标：白天照常上班、领那份安稳的薪水，夜里则一头扎进副业，学技能、接私活、攒第一桶金，谋划着有朝一日能靠一台电脑、一根网线，去任何想去的地方闯天下。理想画得很丰满，可过程是实打实的双倍累——别人下班瘫着，你下班才刚开始第二场战斗。你心里明白，这是在为「自由」二字，提前预付着昂贵的学费。"; } }
    ] },

  // —— 健康习惯养成 ——
  { id: "ev_choice_habit", module: "choice", ambient: true,
    title: "🍔 深夜，胃在叫",
    text: (s) => "加班到深夜，办公室空了，城市也睡了，只有你的胃还醒着，饿得前胸贴后背，咕咕直叫。你点开外卖软件，麻辣烫红亮的汤底、炸鸡金黄酥脆的外壳、火锅翻滚的牛油……一张张图片在屏幕上向你疯狂招手，口水都快下来了。可偏偏这时候，手指划过另一条推送——某个肌肉线条分明的健身博主，配文「自律才有自由，深夜的每一口都算数」。那两个字，此刻看着格外刺眼。这一口下不下肚，你犹豫了。",
    choices: [
      { label: "点份重口外卖，犒劳自己", effect: (s) => { add(s, "mood", 6); add(s, "cash", -50); add(s, "health", -5); add(s, "stress", -3); return "「忙了一整天，凭什么不能对自己好点。」你心一横下了单。半小时后，热腾腾、香喷喷的外卖到了，你顾不上烫就大快朵颐，那股麻辣鲜香顺着喉咙一路下去，仿佛瞬间治愈了一整天积攒的委屈和疲惫。爽，是真的爽，爽到眼眶都有点湿。只是你心里也隐约清楚，体重秤和下一年的体检单，迟早会拿着账本，来找你算今晚这一笔。"; } },
      { label: "忍住，啃个面包对付", effect: (s) => { add(s, "health", 2); add(s, "mood", -4); add(s, "stress", 3); add(s, "body", 1); return "你盯着那些诱人的图片看了足足一分钟，最后一狠心把软件划掉，从抽屉里翻出片放了两天的全麦面包，就着白开水干巴巴地啃了起来。嘴巴是委屈的，心里也别扭，越嚼越觉得索然无味。可当你想起镜子里那块好不容易才有点松动迹象的腹肌，又咬了咬牙——这片寡淡的面包，就是它给你最实在、最不会骗人的奖励。"; } },
      { label: "干脆饿着，早点睡", effect: (s) => { add(s, "health", 3); add(s, "stress", 4); add(s, "mood", -3); return "你索性把外卖软件彻底关掉，又眼不见为净地连手机一起扣在了桌上，灌了一大杯水，骗骗那个闹腾的胃，便倒头睡下。饿着入睡确实是种折磨，半夜里你被空荡荡的胃叫醒了两回，翻来覆去好一阵才迷迷糊糊睡过去。可第二天清醒时，你心里竟有点小小的得意——至少昨晚，你没给本就负债累累的身体，再添一笔新账。"; } },
      { label: "做顿简单的健康餐", effect: (s) => { add(s, "health", 5); add(s, "mood", 3); add(s, "body", 1); add(s, "cash", -30); return "你没点外卖，也没亏待自己，而是走进厨房，支起锅，烧水、下了把青菜、卧了个蛋，几分钟就煮出一碗热气腾腾、清清淡淡的夜宵。比起点开软件等送餐，这多花了你二十来分钟，可一碗下肚，肚子填饱了，身体也没受半点委屈。看着灶台上袅袅升起的热气，那种把生活牢牢攥在自己手里的「掌控感」，让你心里格外踏实安稳。"; } }
    ] },

  // —— 家庭关系：催婚催生 ——
  { id: "ev_choice_pressure_marry", module: "choice", ambient: true,
    cond: (s) => s.age >= 26 && s.age <= 40 && !has(s, "married"),
    title: "🍵 又一场「为你好」的逼问",
    text: (s) => "逢年过节的家庭聚会，一桌子菜还没动几筷子，火力就又一次精准地集中到了你身上。七大姑八大姨你一言我一语，「多大啦还不结婚？」「眼光别太高，再挑就剩下喽」「隔壁谁谁家孩子都生二胎了」，一句句裹着「为你好」的糖衣，砸得你头皮发麻。父母坐在一旁没接话，可你瞥见他们交换的那个眼神，分明写满了藏不住的焦虑和恳求。你握着筷子，脸上的笑越来越僵——这顿饭，这一波逼问，你打算怎么接？",
    choices: [
      { label: "笑着打太极，糊弄过去", effect: (s) => { add(s, "charm", 1); add(s, "mood", -3); add(s, "stress", 4); return "你深谙息事宁人之道，脸上堆起一个无懈可击的笑，「快了快了，有合适的一定第一个告诉您」「来来来，姨我给您夹菜」，三两句太极打下来，话题被你不着痕迹地揉了过去。场面是圆满了，谁也没得罪。可饭局散了、人走茶凉，独自坐在回去的车上，那股被一群人当众围观、品头论足的憋屈，还是堵在胸口，半天散不开。"; } },
      { label: "正面回怼，划清边界", effect: (s) => { add(s, "stress", 6); add(s, "network", -3); add(s, "mood", 2); add(s, "insight", 1); return "你放下筷子，没动怒，却不软不硬、一字一句地把话顶了回去：「谢谢各位长辈关心，不过我的人生，我自己负责，结不结婚、什么时候结，是我自己的事。」饭桌上「啪」地一下安静了，气氛一时有些尴尬，几位长辈面面相觑，讪讪地转了话题。这一回你算是当众碰了她们一鼻子灰，但也立竿见影——从那以后，再没人敢轻易拿这事来烦你了。"; } },
      { label: "顺势开始认真相亲", effect: (s) => { add(s, "network", 2); add(s, "charm", 1); add(s, "cash", -1000); add(s, "stress", 3); flag(s, "blind_date"); return "你心里一动，想着与其被催得心烦，不如主动出击。于是你索性接受了亲戚们热情的「牵线搭桥」，开始了一场又一场的相亲。咖啡馆里，你对面坐过形形色色的人——有聊得来的，有尬到脚趾抠地的。见的人多了，那些不切实际的期待也被现实磨平了不少。可你也没全然失望，毕竟谁说得准呢，说不定哪一场看似平常的会面，转角就遇上了那个对的人。"; } },
      { label: "私下安抚父母，统一战线", effect: (s) => { add(s, "mood", 3); add(s, "charm", 2); add(s, "stress", -2); add(s, "network", 1); return "席间你没和谁起争执，只是默默陪着笑。饭后，你单独把爸妈拉到一边，给他们倒了杯水，掏心窝子地聊了很久。你不争对错，也不讲大道理，只是耐心地让他们明白：你过得很好，你心里有数，你需要的是他们的信任，而不是替你着急。亲戚们那些堵不住的嘴，你管不了。但你想通了——只要父母这两道最坚实的防线站在你这边，外头再多的闲言碎语，也吵不到你心里去。"; } }
    ] },

  // —— 网络舆论 ——
  { id: "ev_choice_online_drama", module: "choice", ambient: true,
    title: "📱 你发的内容上了热评区",
    text: (s) => "你睡前随手发的一条动态，第二天醒来竟然炸了。点赞、转发、评论的红点堆成了一片，提示音响个不停，震得手机在桌上嗡嗡爬。可你点开一看，心却凉了半截——评论区彻底两极分化：有人把你夸上了天，有人逐字逐句地开撕，还有人不知从哪儿扒出你几年前的旧帖，断章取义地带起了节奏。「叮」「叮」「叮」，新消息还在不断涌进来。你的手指悬在屏幕上方，迟迟没敢点下去——这场突如其来的风暴，回应，还是不回应？",
    choices: [
      { label: "有理有据地正面回应", effect: (s) => { add(s, "reputation", 3); add(s, "charm", 1); add(s, "stress", 6); if (rnd(0.5)) { add(s, "network", 4); add(s, "mood", 3); return "你没有被情绪带着走，而是深吸一口气，把质疑一条条列出来，心平气和、有理有据地逐个澄清，逻辑清晰得无懈可击，态度又不卑不亢、落落大方。那些原本观望、甚至带着敌意的理性网友，看完反倒被你的从容圈了粉，纷纷站到你这边。一场眼看要失控的风波，竟被你硬生生扭转成了一次漂亮的高光时刻。"; } add(s, "mood", -5); return "你满心以为讲道理就能平息一切，认认真真打了一大段回应。可你低估了网络的恶意——你的话被人掐头去尾、断章取义，转头就成了新一轮攻击的弹药。你越想解释清楚，对方越是群情激愤、上头较劲，理智在这里根本不通用。最后你只能眼睁睁看着话题彻底失控，沦为一场你压根插不上嘴的狂欢。"; } },
      { label: "懒得理，直接关评论", effect: (s) => { add(s, "stress", -4); add(s, "mood", 1); add(s, "reputation", -1); return "你看了两眼那些刺眼的字，索性大手一挥，把评论区一键关闭——眼不见，心不烦。世界瞬间清静了，提示音也停了，你长舒一口气，把手机往旁边一搁。清静是真清静了，可你不知道的是，那句没说出口的「他这是心虚了吧，不敢面对质疑」，已经悄悄留在了一些围观者的心里，像根看不见的小刺。"; } },
      { label: "删帖跑路，当无事发生", effect: (s) => { add(s, "stress", -2); add(s, "mood", -2); add(s, "reputation", -3); return "你越看越烦，最后一咬牙，把那条惹是生非的动态直接删了个干净，仿佛它从来没存在过。果然，没了载体，热度很快就退了潮，吵闹声散去，一切归于平静。可那种落荒而逃、灰溜溜删帖的感觉，却久久留在心里。从那以后，每当你想再发点什么、想表达点真实想法时，都会下意识地缩回手——你对「发声」这件事，又胆怯了几分。"; } },
      { label: "顺势接住流量，趁热涨粉", effect: (s) => { add(s, "network", 6); add(s, "charm", 2); add(s, "stress", 8); add(s, "reputation", -1); flag(s, "went_viral"); return "你脑子转得飞快——骂声也是流量，泼天的关注不蹭白不蹭。于是你趁热打铁，连着发了好几条乘势追击的内容，节奏踩得又准又狠。果然，粉丝数像坐了火箭，「唰唰唰」地往上蹿，账号一夜起飞。可红利从来都是有代价的：当你发现自己的一举一动都被成千上万双眼睛盯着、解读着、等着挑刺时，那种无形的、密不透风的压力，也悄无声息地爬上了你的肩头。"; } }
    ] },

  // —— 创业邀约 ——
  { id: "ev_choice_join_startup", module: "choice", ambient: true,
    cond: (s) => !has(s, "startup") && s.age <= 45 && !has(s, "goal_family") && !has(s, "goal_peace") && (s.goal === "ipo" || s.goal === "freedom" || s.goal === "corp" || has(s, "risk_hustle") || has(s, "startup_exp")),
    title: "🚀 哥们儿喊你一起创业",
    text: (s) => "深夜的烧烤摊，几瓶啤酒下肚，那个最靠谱的朋友忽然红着眼眶、压低声音跟你交了底：他要创业，想拉你入伙。他越说越激动，给你描绘了一张诱人到发光的蓝图——原始股期权、踩在风口上的赛道、「咱俩说不定真能改变点什么」。他的眼睛在炭火的映照下亮得灼人。你听得热血翻涌，可酒劲过去，理智又冷冷地泼来一盆水：十个创业九个死，剩下那一个也未必活得好，而你眼下这份旱涝保收的安稳工作，真就说扔就扔？",
    choices: [
      { label: "辞职全职加入，赌一把大的", effect: (s) => { add(s, "cash", -5000); add(s, "stress", 14); add(s, "strategy", 3); add(s, "network", 4); add(s, "health", -5); flag(s, "risk_hustle"); return "你最终还是裸辞了。递交辞呈那天，手抖了一下，可心是定的。你一头扎进这场九死一生的牌局，从此告别了月底准时到账的安稳——没了底薪，换来一纸还不知值不值钱的股份。往后的人生只剩两种结局：要么上岸，封神；要么上天台，认栽。这一跳，跳得热血沸腾，也跳得万丈深渊就在脚下。"; } },
      { label: "不辞职，业余参与攒经验", effect: (s) => { add(s, "knowledge", 2); add(s, "insight", 2); add(s, "stress", 8); add(s, "health", -3); return "你选了条最累但也最稳的路：工作不辞，业余入伙。于是你的生活被劈成了两半——白天在公司是规规矩矩的打工人，一到下班和周末，就摇身一变扑进创业的战场，开会、做方案、跑客户。既给自己留足了退路，又实实在在沾上了创业的边、攒下了经验。代价是，你把自己活成了一台没有开关的永动机，连轴转到连做梦都在改PPT。"; } },
      { label: "只出钱当个小股东", effect: (s) => { add(s, "cash", -30000); add(s, "network", 2); add(s, "insight", 1); flag(s, "angel_invest"); if (rnd(0.4)) { return "你不下场拼杀，只掏了一笔钱当个甩手的小股东，把专业的事交给专业的人。你想得通透：这宝要是押对了，往后就是躺着等分红的美事；押错了，权当花钱买了个教训，肉疼但不致命——毕竟你人没搭进去，全身而退的退路始终攥在自己手里。"; } return "你投了一笔钱，没指望它一定开花结果，更多是给老友一份实打实的支持。这项目究竟能不能成，连最乐观的人也说不准。你用真金白银，买来了一个「我也算参与过」的参与感，同时也买来了一份甩不掉的牵挂——往后好些个夜里，你都会替这笔投资多操几分心，跟着账上的数字一起忐忑。"; } },
      { label: "婉拒，安稳才是真", effect: (s) => { add(s, "mood", -2); add(s, "stress", -3); add(s, "insight", 1); add(s, "network", -2); return "你把这事翻来覆去想了好几个晚上，掂量了风险、家庭、自己的承受力，最终还是婉言谢绝了朋友的好意，决定守住眼前这份触手可及的安稳。日子照旧不咸不淡地往前淌，平静得听不见一点水花。只是后来，每当你从别人嘴里听说老友的项目又拿了融资、又上了台阶，你端着咖啡的手，心里总会没来由地、轻轻「咯噔」那么一下。"; } }
    ] },

  // —— 旧友重逢借势 ——
  { id: "ev_choice_old_friend", module: "choice", ambient: true,
    title: "🤝 混得好的老同学找上门",
    text: (s) => "一条微信把你拉回了好多年前——是那个毕业后就断了联系的老同学，约你吃饭。再见面，他已不是当年那个青涩模样：一身得体的行头，举手投足透着掌控感，如今身居要职、人脉广得让人咋舌。席间他给你斟了酒，拍着你肩膀笑得豪爽：「老同学，往后有什么事，尽管开口，别见外！」你举着杯应着，心里却跟明镜似的——这层失而复得的关系，用好了是一架往上爬的梯子，用拧了，就是一笔还不清的人情债。",
    choices: [
      { label: "趁机请他帮个大忙", effect: (s) => { add(s, "network", 5); add(s, "cash", 3000); add(s, "mood", 2); flag(s, "owe_favor"); return "机不可失，你顺着他递来的话头，半试探半认真地提了个一直没辙的请求。他几乎没怎么犹豫，当场一口应下，「这点小事，包在我身上」。没几天，事情果然办得又快又漂亮，你头一回这么真切地尝到了「人脉」二字的甜头。只是夜深下来你也清楚，这份顺水人情不是白来的——它已经记在了账本上，迟早有一天，得连本带「情」地还回去。"; } },
      { label: "只叙旧，不谈利益", effect: (s) => { add(s, "mood", 5); add(s, "charm", 2); add(s, "network", 2); return "整顿饭，你只字未提求他办事，哪怕他几次把话头往那儿引，你也只是笑笑，把话题又拐回当年的操场、宿舍和那些傻乎乎的旧事。你们聊得畅快，纯粹得像还没被社会规训过的少年。他临走时看你的眼神变了，多了几分郑重的高看。你心里明白一个朴素的道理：最牢的交情，往往恰恰是从「不开口求人」开始攒下的。"; } },
      { label: "主动表示愿为他效劳", effect: (s) => { add(s, "network", 4); add(s, "strategy", 2); add(s, "stress", 3); add(s, "charm", 1); return "你没急着开口求他，反倒主动递了话过去：「你那摊子事要是有用得上我的地方，言语一声，别客气。」他愣了一下，随即笑了，眼里多了几分认可。这是一步看得很远的棋——先予后取，你用一份不求回报的实在，在他心里挂了号。你笃定，这条人脉的线，往后只会越走越宽，越走越深。"; } },
      { label: "客气寒暄，保持距离", effect: (s) => { add(s, "insight", 1); add(s, "mood", -1); add(s, "network", -1); return "整场饭局，你都客客气气、滴水不漏，却始终不咸不淡，他几次抛来的橄榄枝，你都笑着含糊带过，没真正接住。你守住了自己那点不愿攀附的清高，也心安理得。可走出饭店、各自上车的那一刻，你心里又掠过一丝说不清的怅然——这究竟是难得的体面，还是白白错过的机会，恐怕只有往后的日子才能给你答案了。"; } }
    ] },

  // —— 突发：路遇求助 ——
  { id: "ev_choice_street_help", module: "choice", ambient: true,
    title: "🆘 街角，有人向你求助",
    text: (s) => "天擦黑，你正赶着回家，路边一个人忽然神色慌张地拦住你。他衣着还算体面，却一脸窘迫，语速很快：手机没电、钱包不知在哪儿丢了，身上一分钱没有，回不了家，想跟你借两百块应应急，说着掏出手机要记下你的账号，「到家立马还您，真的，我XX单位的」。他说得情真意切，眼眶都有点红。你将信将疑——这年头，最动人的故事，往往也是最精心编排的剧本。这个人，你信几分？",
    choices: [
      { label: "掏钱相助，宁可信其有", effect: (s) => { add(s, "cash", -200); add(s, "mood", 4); add(s, "reputation", 1); if (rnd(0.55)) { add(s, "network", 1); return "你心一软，掏出两百块递了过去，「拿着吧，回家要紧」。他千恩万谢地记下了你的联系方式。本以为这事八成没了下文，谁知没过几天，转账真的到了账，还附着一长串掏心窝子的感谢。你笑了笑——世道再凉，你那点不设防的善意，恰好捂热了一个素不相识的人，也捂热了你自己。"; } add(s, "insight", 1); return "你心一软，掏出两百块递了过去。他千恩万谢、连鞠了好几个躬，转身消失在人流里，然后……就再没有然后了。账号没收到一分钱，那个「单位」你也无从查起。你被结结实实地骗了一回。可你转念又想：两百块买个心安，权当行善积德了，亏，也亏不到哪儿去。你宁愿偶尔被骗，也不愿练就一颗谁都不信的硬心肠。"; } },
      { label: "不给钱，帮忙报警 / 联系家人", effect: (s) => { add(s, "strategy", 1); add(s, "insight", 1); add(s, "mood", 1); return "你没急着掏钱，而是平静地提议：「这样吧，我帮你报个警，或者你报家里电话，我帮你拨，让家人来接你。」这一招最妙——倘若他是真遇了难，这是实打实能解决问题的正路，他会感激；倘若他是设局行骗，这条路堵死了他的剧本，对方多半会脸色一变、讪讪地找借口溜走。你既没冷着一颗心见死不救，也没傻乎乎地往套里钻。"; } },
      { label: "请他吃顿饭，不给现金", effect: (s) => { add(s, "cash", -40); add(s, "mood", 3); add(s, "charm", 1); return "你没给现金，却朝路边那家还亮着灯的小馆子一指：「走，我请你吃碗热乎的，吃饱了再想办法。」这一下，真假立辨——真饿了一天的人,会顾不上体面地狼吞虎咽；而冲着钱来的人，则会在热气腾腾的饭菜前坐立难安、食不知味，找个由头匆匆离开。你这份善意给得有温度，也给得有分寸，不冷血，也不犯傻。"; } },
      { label: "礼貌拒绝，快步离开", effect: (s) => { add(s, "insight", 1); add(s, "mood", -2); return "你抱歉地摆了摆手，「不好意思，我也没带现金」，没等他再开口，便加快脚步绕了过去，心里默念着「现在的骗子，戏一个比一个足」。也许，你刚刚机敏地躲过了一个精心设计的套路；也许，你恰好辜负了一个真正走投无路的人。走出去老远，你回头看了一眼，那个身影还站在原地。这道题的答案，你这辈子大概都不会知道了。"; } }
    ] },

  // —— 职业转型 ——
  { id: "ev_choice_career_switch", module: "choice", ambient: true,
    cond: (s) => s.age >= 28 && (!!s.job || has(s, "employed")),
    title: "🔀 干腻了，想换条路",
    text: (s) => "在这一行摸爬滚打好些年了，曾经的新鲜与热望，早被日复一日的重复磨成了麻木。最近你越来越提不起劲，对着电脑发呆的时间越来越长。一个「转行」的念头像野草，反复从心底冒出来，怎么拔也拔不净。可一旦认真盘算，现实立刻泼来冷水：转行意味着工资腰斩、多年积累清零、从头当学徒，还要硬着头皮和一帮比你小一轮、学得又快的年轻人抢饭碗。你站在这座职业围城的门口，进退维谷，踌躇了很久很久。",
    choices: [
      { label: "果断转行，追自己想要的", effect: (s) => { add(s, "cash", -8000); add(s, "knowledge", 3); add(s, "mood", 5); add(s, "stress", 8); add(s, "reputation", -3); flag(s, "career_switch"); return "你一狠心，纵身跳进了那片向往已久的新领域。代价来得又快又狠：工资直接腰斩，多年熬出来的资历归了零，你重新变回那个什么都得问、什么都得学的新人。日子是紧巴了不少，得精打细算。可奇妙的是，每天清晨睁开眼，你眼里又有了光，有了那种「为自己想要的东西奔忙」的鲜活劲儿——这股劲，是再多钱也买不来的。"; } },
      { label: "骑驴找马，边干边铺路", effect: (s) => { add(s, "knowledge", 2); add(s, "insight", 2); add(s, "stress", 6); add(s, "health", -2); return "你没被一时冲动冲昏头，没有潇洒裸辞，而是选了条更稳妥也更熬人的路：一边稳稳守着现在的饭碗，一边利用所有零碎时间，悄悄给转行那条新路铺砖添瓦——学课程、考证书、攒作品。进度慢得让人着急，人也累得像两头烧的蜡烛。但你想得明白：输不起的人，就该把退路留足了再迈步，稳扎稳打，才走得远。"; } },
      { label: "内部转岗，风险小一点", effect: (s) => { add(s, "strategy", 2); add(s, "network", 2); add(s, "mood", 2); add(s, "knowledge", 1); return "你没往外跳，而是把目光转回了公司内部。你私下找老领导喝了杯茶，又托了几个熟络的同事打听，最终争取到了一个心仪岗位的转岗机会，借着多年攒下的老关系，平平稳稳地软着陆。跨度没大到让你伤筋动骨，新鲜感自然也没那么足。但好歹，你没赌上全部身家，就给自己有些倦怠的职业生涯，体面地换了条新赛道。"; } },
      { label: "忍住，干一行专一行", effect: (s) => { add(s, "knowledge", 3); add(s, "mood", -3); add(s, "stress", 2); add(s, "cash", 1000); return "你最终还是把那股蠢蠢欲动的冲动，硬生生按了回去，决定继续在这条熟悉的老路上深耕下去。少了点另起炉灶的新鲜与刺激，日子难免显得有些平淡乏味。可你也渐渐想通了——这世上从没有不腻的工作，只有日积月累垒起来的专业壁垒。当你在这行钻得足够深，你便慢慢成了那个别人绕不开、替不掉的人。这份「无可替代」，本身就是一种底气。"; } }
    ] },

  // —— 健身受伤抉择 ——
  { id: "ev_choice_injury", module: "choice", ambient: true,
    cond: (s) => (s.health || 70) >= 40,
    title: "🤕 运动时拉伤了",
    text: (s) => "状态正好的一次冲刺训练，你脚下发力，膝盖却毫无预兆地「咔」一声，一阵尖锐的刺痛瞬间窜遍全身，你整个人差点栽倒。诊室里，医生对着片子皱起眉，给了你两个都不轻松的选项：要么老老实实彻底休养几个月，把它养透；要么忍着痛接着练，但很可能落下一辈子甩不掉的隐患。你坐在诊室的塑料椅上，心里五味杂陈——好不容易才找到的那点运动节奏、那份久违的掌控感，竟被这「咔」的一下，硬生生打断了。",
    choices: [
      { label: "乖乖休养，彻底养好再说", effect: (s) => { add(s, "health", 6); add(s, "body", -1); add(s, "mood", -4); add(s, "stress", 3); return "你听了医生的话，咬牙把训练彻底停了，绑上护具、按时复健，把身体的恢复摆在了第一位。伤确实在一天天好转，疼痛慢慢退去。可眼看着好不容易练出来的那点体能、那身刚有起色的线条，一寸一寸地退了回去，你心里就直犯堵——理智上你知道这是对的，可看着自己「打回原形」，那滋味实在不好受。"; } },
      { label: "忍痛继续，怕断了节奏", effect: (s) => { add(s, "body", 2); add(s, "health", -8); add(s, "mood", 2); add(s, "stress", 4); flag(s, "old_injury"); return "你舍不得这来之不易的节奏，索性给膝盖缠上厚厚的护具，吞下两片止痛药，咬着牙继续上。状态是硬生生保住了，训练没断档，你心里那点「我没被打倒」的倔强也得到了满足。可你也清楚，隐患就这么悄悄埋下了。它不会马上发作，却会在往后某个阴雨绵绵的天，从骨头缝里钻出来，一遍遍提醒你：当年逞的那点强，迟早是要连本带利还回来的。"; } },
      { label: "换个不伤膝盖的项目", effect: (s) => { add(s, "health", 4); add(s, "body", 1); add(s, "insight", 1); add(s, "mood", 2); return "你既没硬扛着把自己练废，也没就此心灰意冷地躺平，而是上网查资料、咨询教练，转头研究起那些对膝盖更友好的温和运动——游泳、骑行、普拉提。换了条路，照样能挥汗如雨，还顺带啃了不少运动损伤和身体构造的知识，对怎么科学地待自己的身体有了全新的认识。塞翁失马，焉知非福——有时候，被迫绕的那条路，反倒让你看见了更开阔的风景。"; } },
      { label: "干脆放弃运动，省心省力", effect: (s) => { add(s, "mood", 2); add(s, "stress", -3); add(s, "health", -3); add(s, "body", -2); return "说实话，坚持运动这事本就靠着一股劲撑着，这一伤，倒成了你顺水推舟的台阶。你索性借坡下驴，把跑鞋塞进了鞋柜最深处，运动这件事，就这么彻底搁置了。没了训练的酸痛和早起的煎熬，日子是清闲轻松了不少。只是偶尔翻到从前那些大汗淋漓、眼神发亮的照片，你会愣一下神——那个曾经挥汗如雨、自律满满的自己，好像又离你远了一些。"; } }
    ] },

  // —— 父母赡养 ——
  { id: "ev_choice_parents_care", module: "choice", ambient: true,
    cond: (s) => s.age >= 30,
    title: "🏥 父母年纪大了",
    text: (s) => "电话那头，是父母熟悉又陌生的声音。问起身体，他们照例含含糊糊地搪塞：「没事没事，就是有点不舒服，老毛病了，你忙你的。」可你太了解他们了——这「没事」两个字背后，藏着的恰恰是怕你担心、报喜不报忧的小心翼翼。你握着手机，心猛地揪了一下：他们是真的老了，腰弯了，话也絮叨了，而你呢，远隔千里，忙得脚不沾地，连一通完整的电话都常常说不完就被工作打断。这份沉甸甸的牵挂压在心头——这事，你到底该怎么安排？",
    choices: [
      { label: "请假回家，亲自照料", effect: (s) => { add(s, "mood", 6); add(s, "health", -2); add(s, "cash", -3000); add(s, "reputation", -2); add(s, "stress", 4); return "你什么都没多想，跟领导请了假，订了最近一班车票，撇下手头那些「天大的正事」就往家赶。接下来的日子，你陪床、煎药、起早排队挂号、扶着他们在医院长长的走廊里慢慢走。工作是耽误了不少，回去少不了要补窟窿。可某个深夜，你守在病床边，看着父母因为有你在身边而格外踏实安稳的睡颜，忽然就鼻子一酸——什么晋升、什么KPI，此时此刻，都远远比不上能陪在他们身边。"; } },
      { label: "出钱请护工 / 找最好的医院", effect: (s) => { add(s, "cash", -15000); add(s, "mood", 2); add(s, "stress", 2); add(s, "insight", 1); return "你抽不开身，便用最擅长的方式尽孝——掏钱。你托关系挂上了最好医院的专家号，又请了经验丰富、口碑极佳的护工，把能想到的周全照料都安排得妥妥帖帖，自己则继续留在异乡的战场上拼命挣钱，好让这份「周全」能一直维持下去。物质上，你确实问心无愧地尽了力。可每到夜深人静，那句「子欲养而亲不待」，还是会毫无防备地冷不丁刺你一下，疼得你睡不着。"; } },
      { label: "接父母到身边一起住", effect: (s) => { add(s, "cash", -8000); add(s, "mood", 4); add(s, "stress", 6); add(s, "network", 1); flag(s, "parents_live_with"); return "你下了决心，把父母从老家接到了身边，想着一家人朝夕相处，再不必隔着电话干着急。重新团圆的头几天，家里确实热闹了不少，饭桌上有了说笑，灯也亮到了更晚。可日子一长，新的磕碰也悄悄冒了出来——两代人迥异的作息、消费观、育儿观，逼仄空间里被放大的生活习惯差异，一点点磨着彼此。你这才体会到，孝顺有时不是把人接来就够了，更难的是接来之后，如何让两代人在同一个屋檐下，都过得舒坦。"; } },
      { label: "电话多关心，暂时顾不上", effect: (s) => { add(s, "mood", -6); add(s, "stress", 5); add(s, "cash", 500); return "现实把你死死按在原地——项目走不开，假请不下来，机票说走就走的潇洒你也学不来。你能做的，只是把电话打得更勤些，多问几句吃得好不好、睡得香不香，叮嘱他们按时吃药、有事千万别瞒着。理智上，你有一万个「身不由己」的理由，每一个都站得住脚。可那份「在他们最需要的时候，我却不能守在身边」的愧疚，像块湿冷的石头压在心口，怎么搬，也搬不走。"; } }
    ] },

  // —— 买房抉择 ——
  { id: "ev_choice_buy_house", module: "choice", ambient: true,
    cond: (s) => !has(s, "has_house") && s.cash > 100000,
    title: "🏠 要不要上车买房",
    text: (s) => byClass(s, {
      poor: "你打开存款页面，看着那个攒了好多年、省吃俭用一分一分抠出来的数字，掂量再三——勉勉强强，够个首付了。可窗外的房价高得吓人，每个数字后面都跟着一串让人窒息的零。你心里清楚，在这座偌大的城市里，没有一处真正属于自己的窝，无论住多少年，你始终像个随时会被请走的过客。这一步，是咬牙迈出去，还是再等等？",
      mid: "首付总算凑得七七八八了，可你反倒更纠结了：是一脚上车、背上长达三十年的房贷，从此被牢牢拴住；还是继续租房，把钱攥在手里、把人生保持在「随时可以重来」的灵活状态？身边的人，买的买、观望的观望，各有各的道理，吵得你脑子嗡嗡响，你自己也实在拿不定主意。",
      rich: "买不买房，对你而言早已不是「能不能」的问题，而不过是资产配置棋盘上的一步棋。你呷着咖啡，慢条斯理地盘算：是图个安心、落袋为安，在核心地段置一套优质资产；还是把这笔钱投向别处，去追逐更高的回报率？纯粹是一道关于收益与偏好的算术题，不带半分焦虑。"
    }),
    choices: [
      { label: "上车买房，要个安定", effect: (s) => { add(s, "cash", -100000); add(s, "assets", 200000); add(s, "mood", 6); add(s, "stress", 8); flag(s, "has_house"); return "你深吸一口气，在那一沓厚厚的合同上签下了名字——掏空了多年的积蓄，又背上了一笔长得看不到头的贷款，换来一套实打实、写着自己名字的房子。拿到钥匙、第一次打开属于自己的门那一刻，你心里某块漂泊已久的地方，终于落了地。可与此同时，那串每月雷打不动的还款数字，也像一座沉默的大山压上了肩头，让你往后无论想跳槽、想任性、想停下来喘口气，都得先掂量掂量它的分量。"; } },
      { label: "继续租房，保持灵活", effect: (s) => { add(s, "cash", -2000); add(s, "stress", -4); add(s, "insight", 2); return "你想通了，决定不当那个被三十年贷款拴住的「房奴」，而是把这笔钱牢牢攥在自己手里，换取一份说走就走的自由——想换城市就换城市，想换工作就换工作，人生始终留着回旋的余地。代价是，住得再久的出租屋，墙上也不敢钉钉子，心里总缺那么一份扎根的归属感。至于往后房价是涨是跌——那是另一道你押了「不上车」的赌局，输赢，留给时间去揭晓。"; } },
      { label: "买套小的过渡，先上车", effect: (s) => { add(s, "cash", -60000); add(s, "assets", 110000); add(s, "mood", 3); add(s, "stress", 4); flag(s, "has_house"); return "你不想被高昂的总价彻底压垮，又实在放不下那点对「家」的执念，于是退而求其次，先上了辆「小车」——一套面积不大、地段也一般的过渡房。空间是局促了点，转个身都得侧着走，可好歹，你在这座城市里有了一处真正落脚生根的地方。你安慰自己：先扎下根来，等往后翅膀硬了、底气足了，再换套大的也不迟。日子，总是一步一步往上走的。"; } },
      { label: "把钱拿去投资增值", effect: (s) => { add(s, "stress", 6); if (rnd(0.45)) { add(s, "assets", 60000); add(s, "insight", 2); return "你没把这笔钱砸进钢筋水泥里，而是赌「钱生钱」的速度能跑赢房价的涨幅。这一把，你赌赢了，而且玩得相当漂亮——资产实打实地往上翻，收益远超你当初要是买房能有的增值。你看着账户里令人愉悦的数字，暗自庆幸：还好当初没被「人人都得上车」的执念绑架，理性，有时候比随大流更值钱。"; } add(s, "cash", -40000); add(s, "mood", -6); return "你把那笔本该当首付的钱投了出去，满心期待它能开出花来。可市场偏偏不给你面子，一波震荡下来，本金不增反缩，绿了一片。更让你五味杂陈的是，你眼睁睁看着当初看中的那套房，房价还在一个劲儿地往上爬。两头一对比，你坐在屏幕前，心里那叫一个说不出的滋味——早知如此，当初是不是该老老实实上车？"; } }
    ] },

  // —— 同学聚会攀比 ——
  { id: "ev_choice_reunion", module: "choice", ambient: true,
    cond: (s) => s.age >= 25,
    title: "🍻 同学会上的隐形较量",
    text: (s) => byClass(s, {
      poor: "阔别多年的同学会，包间里推杯换盏好不热闹。可你越坐越不是滋味——当年成绩平平、调皮捣蛋的那几个，如今西装革履，停车场停着豪车，张口闭口都是大生意、大项目，言语间那股不经意流露的优越感，像针一样扎人。你攥着手里的杯子，杯壁的凉意一路凉到心里，那点「怎么就我混得不如人」的局促和自卑，悄没声儿地爬上了心头。",
      mid: "酒桌上，所有人都默契地玩着同一个游戏：明面上叙旧情、忆当年，暗地里房子、车子、孩子、年薪，一轮接一轮地较着劲。你恰好卡在不上不下的中游，比上不足、比下有余，听着左边的炫耀、右边的哭穷，心里那杆原本还算平稳的秤，不知不觉开始一点点失衡、晃动。",
      rich: "如今你已是同学里数一数二的人物，一进门，目光和笑脸便齐刷刷地围拢过来，敬酒的、寒暄的、欲言又止想攀关系的，络绎不绝。你端着杯子，脸上挂着得体的笑，应对得游刃有余。只是在这一片热络的捧场声里，你心里跟明镜似的，清清楚楚地分得出：哪些是几十年没变的真心，哪些，不过是冲着你今时今日的身价来的。"
    }),
    choices: [
      { label: "也跟着吹一波，撑住面子", effect: (s) => { add(s, "charm", 1); add(s, "cash", -2000); add(s, "mood", 2); add(s, "stress", 4); return "你不甘示弱，也跟着把自己里里外外包装了一番，言语间添油加醋，末了还抢在所有人前头把单给买了，「来来来，今天我请！」那一刻，灯光下你确实风光无两，赚足了面子。可饭局散尽，你独自瘫在家里的沙发上，账单的肉疼和那种「打肿脸充胖子」的空虚一起涌上来——别人骗得过，你骗不过自己。"; } },
      { label: "坦然做自己，不卑不亢", effect: (s) => { add(s, "mood", 4); add(s, "insight", 2); add(s, "charm", 1); return "你既不攀比，也不自卑，只是平平静静地做自己。别人问起，你大方坦承自己的普通和平凡，没什么好遮掩的；听到老同学真有出息，你也真心实意地为他鼓掌叫好，没有半分酸味。奇妙的是，这份不端着、不较劲的松弛，反倒成了满桌最稀缺、最有底气的东西。散场时，好几个老友拍着你肩膀感慨：「聊了一圈，还是跟你说话最舒服、最自在。」"; } },
      { label: "默默观察，把人脉记心里", effect: (s) => { add(s, "network", 3); add(s, "strategy", 2); add(s, "insight", 1); add(s, "mood", -2); return "你话不多，更多时候只是端着杯子，安安静静地听、不动声色地看。谁手里攥着真资源、谁只是嘴上风光、谁为人靠谱值得深交、谁又虚头巴脑只能远观——你在心里一笔一笔默默盘点、悄悄归档。那些攀比的、炫耀的话，左耳进右耳出，你压根没往心里去。你真正惦记的，是这场热闹散去之后，哪几根线，日后或许真能为你所用。"; } },
      { label: "受刺激了，回去更拼", effect: (s) => { add(s, "stress", 6); add(s, "strategy", 2); add(s, "mood", -3); add(s, "health", -2); flag(s, "fired_up"); return "这一顿饭，把你刺得整宿整宿睡不着。躺在床上，那些刺耳的对比、别人轻描淡写的「成功」，一遍遍在脑子里循环播放。你暗暗咬牙较上了劲：「凭什么我就比他们差？」回去之后，你像换了个人，玩命般地扑进工作里，把那股巨大的落差感，硬生生淬炼成了往前冲的燃料。只是你也隐隐感到，这把火烧得太急、太猛——照亮前路的同时，也在一点点灼烧着你自己。"; } }
    ] },

  // —— 突然的空闲长假 ——
  { id: "ev_choice_long_holiday", module: "choice", ambient: true,
    title: "🏖️ 难得的一个长假",
    text: (s) => "压了几个月的大项目，终于在某个深夜画上了句号。当你把最后一封交付邮件发出去，那种紧绷已久的弦「啪」地松开的感觉，几乎让你瘫软在椅子上。更妙的是，攒下的调休凑成了一个完完整整、无人打扰的长假。难得能这么彻底地放空，可怎么把这几天用得不留遗憾，竟又成了一种甜蜜的烦恼。你瘫在床上，盯着天花板盘算：这难得的几天，你想怎么活？",
    choices: [
      { label: "来一场说走就走的旅行", effect: (s) => { add(s, "cash", -6000); add(s, "mood", 10); add(s, "insight", 2); add(s, "stress", -8); add(s, "health", -1); return "你订了张最近的票，简单收拾个包就出发了，目的地都是临时定的。你看到了从没看过的风景，吃了叫不出名字的小吃，和陌生人攀谈，在异乡的街头漫无目的地走。钱是花得有点心疼，回来还得勒紧裤腰带。可那些新鲜的人、新鲜的事，像一块湿布，把你被日复一日的工作磨得迟钝、麻木的感官，一点一点重新擦亮了。你这才想起，原来活着，本该是这般有色彩的。"; } },
      { label: "宅家彻底躺平回血", effect: (s) => { add(s, "health", 8); add(s, "stress", -12); add(s, "mood", 4); add(s, "knowledge", -1); return "你哪儿也不去，把自己彻底交给了那张床和那张沙发。睡到日上三竿、昏天黑地，醒了就刷剧、点外卖，刷到连今天是周几、几号都彻底搞不清。没有闹钟，没有deadline，没有任何人催你。几天下来，亏空已久的身体和精神都满血复活，整个人轻飘飘的。只是当假期的最后一晚悄然来临，你回想这几天，竟发现它像一阵风，舒服是真舒服，却也什么痕迹都没留下。"; } },
      { label: "闭关搞个人项目 / 充电", effect: (s) => { add(s, "knowledge", 5); add(s, "mind", 2); add(s, "insight", 2); add(s, "stress", 3); add(s, "health", -2); return "别人眼里的「假期」，被你过成了一段无人打扰的「冲刺期」。你关掉社交软件，泡上一壶茶，一头扎进那个一直想做却没空做的个人项目，或是啃下一门觊觎已久的新技能。窗外是别人嬉笑游玩的声音，屋里是你敲键盘、记笔记的沙沙声。累，是真累，可你心里有种隐秘的笃定——当别人在玩的时候你在长本事，这几天悄无声息的积累，正一点点拉开你和同龄人之间的身位。"; } },
      { label: "陪伴家人 / 处理人情往来", effect: (s) => { add(s, "mood", 6); add(s, "network", 3); add(s, "charm", 1); add(s, "cash", -2000); return "你把这难得的假期，整个儿还给了那些被你忙碌时冷落了太久的人。你回了趟老家陪父母吃了几顿家常饭，约了几个许久没见的老友叙旧，还走访了几家平日里疏于走动的亲戚。没有什么轰轰烈烈的大事，无非是些家长里短、推杯换盏。可正是这些琐碎的陪伴，让那些因疏于联系而渐渐变凉的关系，重新有了热乎乎的温度——有些账，是金钱补不回来的。"; } }
    ] },

  // —— 工作机会取舍 ——
  { id: "ev_choice_offer", module: "choice", ambient: true,
    cond: (s) => s.age >= 24 && s.age <= 50,
    title: "📨 两个 offer 摆在面前",
    text: (s) => "命运有时就爱出难题。你面前的桌上，并排躺着两封 offer：一份来自人人艳羡的大厂，薪水诱人、名头响亮，可圈内人都知道那是个出了名的「卷王窝」，加班是家常便饭；另一份来自一家不起眼的小公司，钱少、活杂、什么都得自己上手，却胜在清闲自在、不必把命搭进去。猎头的电话一个接一个，催你尽快答复。手机屏幕亮了又暗——鱼和熊掌，这一回，你只能取其一。",
    choices: [
      { label: "进大厂，趁年轻搏一把", effect: (s) => { add(s, "cash", 30000); add(s, "reputation", 5); add(s, "network", 4); add(s, "health", -6); add(s, "stress", 12); add(s, "mood", -2); flag(s, "bigtech"); return "你按下了大厂那份 offer 的确认键，心想趁着年轻不搏一把，更待何时。入职后，薪水实打实地翻了番，简历上多了块金光闪闪的招牌，开口报出公司名，别人的眼神都不一样了。可硬币的另一面同样真实——常态化的 996，深夜空荡的写字楼，和被一天天透支的身体。你确实站上了更高的平台，看见了更远的风景；但你也踏上了一台永不停歇、越转越快的跑步机，再难下来。"; } },
      { label: "去小公司，求个生活平衡", effect: (s) => { add(s, "health", 5); add(s, "stress", -8); add(s, "mood", 6); add(s, "cash", -3000); add(s, "insight", 1); return "权衡再三，你挑了清闲的那一份，把「生活」二字重新放回了天平上。钱是少了一截，得精打细算着过，但你换回了准点下班的傍晚、能好好吃饭睡觉的夜晚，和一份久违的从容。同事们都羡慕你那份不慌不忙的松弛。只是偶尔，当你刷到曾经那个 offer 所在的大厂、看到那令人咋舌的薪资水平时，你也会忍不住愣上那么一下神——人嘛，总会忍不住想象另一条没走的路。"; } },
      { label: "选有成长性的，赌未来", effect: (s) => { add(s, "knowledge", 4); add(s, "strategy", 2); add(s, "insight", 2); add(s, "stress", 6); return "你没盯着眼前的薪资条做决定，而是把目光投向了更远的地方，挑了那个最能学到真东西、最有上升空间和想象力的选项。短期来看，回报平平，甚至有点亏。可你心里有本更长远的账——你押注的，不是此刻口袋里多几个钱，而是三年、五年之后，那个被狠狠历练过、本事更硬、也更值钱的自己。这是一场对未来的下注。"; } },
      { label: "都不满意，再观望观望", effect: (s) => { add(s, "stress", 4); add(s, "cash", -2000); add(s, "insight", 1); if (rnd(0.4)) { add(s, "mood", 4); return "你权衡再三，觉得这两份都不够「对」，索性谁也没接，沉住气继续等。这份耐心需要底气，等待的日子里你也忐忑过。可命运这次奖励了你的笃定——没过多久，一个比之前两份都更合心意的机会主动找上门来。你长舒一口气，庆幸自己当初没有将就。有时候，敢于等待，本身就是一种实力。"; } add(s, "mood", -5); return "你挑来拣去，总觉得这山望着那山高，结果两份 offer 的答复期一过，全都黄了。更倒霉的是，紧接着市场行情急转直下，招聘冻结、裁员的消息满天飞，你眼巴巴地等啊等，再也没等来那个「更好的」。漫长的空窗期里，你看着日渐缩水的存款，后悔得直拍大腿——原来有时候，「将就」并不是妥协，而是一种清醒。"; } }
    ] },

  // —— 邻里/物业纠纷 ——
  { id: "ev_choice_neighbor", module: "choice", ambient: true,
    title: "🔊 楼上又开始装修了",
    text: (s) => "已经连着一个礼拜了。楼上的电钻声从清早六点准时响起，一直突突突地干到天黑，墙都在跟着震，你那点本就金贵的休息时间被搅得稀碎，头疼得太阳穴突突直跳。前两天你上楼好声好气沟通过一回，对方却爱搭不理，敷衍两句就关了门。一股怒火噌噌往脑门上蹿，可你也犯难——同一栋楼，抬头不见低头见的，真闹翻了往后几年都尴尬。这事，到底该怎么了结？",
    choices: [
      { label: "上门理论，必须给个说法", effect: (s) => { add(s, "stress", 4); add(s, "mood", 2); add(s, "network", -2); add(s, "body", -1); return "你忍无可忍，「噔噔噔」上了楼，抬手就是一阵急促的敲门，当面把话挑明。两边话赶话，火气越说越大，一度差点拍了桌子。最后对方理亏，悻悻地答应往后错开你休息的时段施工。问题总算解决了大半，电钻声消停了些。可你心里也清楚，这一通对峙下来，邻里间的那点情面是撕破了，这梁子，往后是结下了。"; } },
      { label: "找物业 / 走正规投诉", effect: (s) => { add(s, "strategy", 1); add(s, "insight", 1); add(s, "stress", 2); if (rnd(0.6)) { add(s, "mood", 3); return "你没自己上门硬碰硬，而是按规矩走流程，拨通了物业电话、留了书面记录，请他们出面调解。物业果然管用，上门一沟通，对方也守了规矩，把施工时间规规矩矩地调开了。一场眼看要升级的邻里冲突，就这么不动声色地化解了，谁的脸都没撕破。你由衷感慨：很多时候，「按规则办事」远比逞一时之快，要高明得多。"; } add(s, "mood", -3); return "你老老实实走了正规流程，满心指望物业能主持公道。谁知物业是个十足的「和事佬」，上门转了一圈，这边劝劝、那边哄哄，话说得滴水不漏，问题却一个也没真解决。挂了电话没多久，楼上的电钻又准时突突突地响了起来。你不仅没讨着说法，反倒白白搭进去一肚子气，憋得胸口发闷。"; } },
      { label: "买副降噪耳机，眼不见为净", effect: (s) => { add(s, "cash", -1000); add(s, "mood", 1); add(s, "stress", -3); add(s, "knowledge", 1); return "你懒得跟人置气，干脆下单了一副口碑不错的降噪耳机。东西到手，往耳朵上一戴，电钻声「唰」地一下被隔绝在了另一个世界，整个人瞬间清静了。问题本身一点没解决，楼上照样在凿，但你聪明地绕开了它，把闹心的事屏蔽在了自己的小气泡之外。你忽然觉得——有时候，舍得花点钱给自己买份清净，未尝不是一种成熟。"; } },
      { label: "忍忍就过去了，多一事不如少一事", effect: (s) => { add(s, "stress", 6); add(s, "mood", -5); add(s, "health", -2); return "你叹了口气，选择了硬扛，一遍遍在心里念叨「多一事不如少一事，装修总有结束的那天」。脾气是愣是没发出来，面子上一团和气。可那股活生生被堵在胸口、咽不下又吐不出的窝火，却没处消散，连着好几个晚上，你都被楼上的噪音和自己翻腾的情绪搅得辗转反侧，睡不安生。忍，有时候是退一步海阔天空，有时候，却只是在慢慢消耗自己。"; } }
    ] },

  // —— 公益与回馈 ——
  { id: "ev_choice_charity", module: "choice", ambient: true,
    cond: (s) => s.cash > 5000,
    title: "❤️ 一封劝募的私信",
    text: (s) => "睡前刷手机，一条私信跳了出来——是个看上去揪心又真实的求助：可能是山里的孩子凑不齐下学期的学费，照片上那双怯生生又渴望的眼睛盯着你；也可能是某个素不相识的重病者，正为高昂的治疗费走投无路地众筹。捐款链接和收款码就静静躺在那里，触手可及。你心头猛地一软，几乎就要点下去。可指尖悬住的那一秒，另一个念头又冒了出来：这年头，真真假假，谁分得清？你这份善意，到底该往哪儿放，才不被辜负？",
    choices: [
      { label: "慷慨解囊，能帮一点是一点", effect: (s) => { add(s, "cash", -2000); add(s, "mood", 6); add(s, "reputation", 2); return "你没让那点怀疑拖住自己的手，几乎是没多想，就捐了一笔过去。数目算不上大，对你的生活构不成什么影响。可一想到这点钱或许真能给某个素未谋面的人，雪中送上一点点温暖、一点点希望，你心里就涨满了暖意。你对自己说：哪怕这世上真有那万分之一的可能是假的，这份发自本心的善良，也一点都没白给。"; } },
      { label: "先核实，再决定捐不捐", effect: (s) => { add(s, "insight", 2); add(s, "strategy", 1); add(s, "mood", 1); add(s, "cash", -500); return "你没被情绪牵着鼻子走，而是先冷静下来，顺着信息一点点查证：发起平台正不正规、求助信息对不对得上、有没有官方背书。直到确认确有其事、靠谱可信，你才放心地捐了一笔小额。你信奉一个道理——理性的善良，才能走得更远。这一回，你既实实在在地献出了爱心，又没让那份好心，沦为别有用心者收割的「智商税」。"; } },
      { label: "不捐钱，转发帮忙扩散", effect: (s) => { add(s, "network", 1); add(s, "reputation", 1); add(s, "charm", 1); return "你手头不算宽裕，没掏钱，却也没就此划走，而是顺手把这条求助转发到了几个群和朋友圈，配上一句「核实过，希望能帮到」。在你看来，这不过是举手之劳，可对那个深陷困境的人来说，你这一声吆喝，说不定就能在人海里多激起几圈涟漪，多换来几份善款。你忽然明白——有时候，没有余力出钱，能站出来替别人喊一嗓子，同样是一种实实在在的力量。"; } },
      { label: "划走，骗局太多懒得管", effect: (s) => { add(s, "insight", 1); add(s, "mood", -2); return "你盯着那个收款码看了几秒，到底还是叹了口气，手指一滑划了过去，心里默念着「现在这种骗局太多了，被坑过的人还少吗」。也许，你刚刚精明地躲过了一个精心设计的套路，省下了一笔可能打水漂的钱；也许，你恰恰错过了一次真正能温暖他人的机会，辜负了一份真实的求救。那点划走时一闪而过的犹豫，像颗小石子，在你心里轻轻地、不易察觉地硌了一下。"; } }
    ] },

  // —— 退休/晚年生活方式 ——
  { id: "ev_choice_retire_life", module: "choice", ambient: true,
    cond: (s) => s.stageId === "senior" || s.stageId === "elder" || s.age >= 55,
    title: "🌅 忙活了大半辈子，往后怎么过",
    text: (s) => "退休的日子，眼看着一天天近了。操劳了大半辈子，每天被闹钟、打卡、KPI追着跑的你，第一次拥有了大把大把、可以随意挥霍的时间。可奇怪的是，这突如其来的空闲，不但没让你松快，反倒让你有些无所适从——清晨醒来不必赶着出门，竟有几分茫然。你坐在窗边，看着楼下慢悠悠遛弯的老人，认真地问自己：往后这剩下的、终于完全属于自己的岁月，到底该怎么过，才算不辜负？",
    choices: [
      { label: "发挥余热，返聘 / 搞点事业", effect: (s) => { add(s, "cash", 8000); add(s, "mind", 1); add(s, "stress", 4); add(s, "health", -3); add(s, "network", 2); return "你是个闲不住的性子，刚退下来没几天就浑身不自在，于是欣然接受了返聘，或是张罗起一摊自己一直想做的小事业。重新有了奔头，收入和那份「我还有用」的价值感都回来了，脑子天天转着也没生锈，反倒比同龄人精神矍铄。只是夜深歇下时，这把年纪还在拼，身体偶尔会发出几声不易察觉的抗议，提醒你：服老，或许也是一种智慧。"; } },
      { label: "培养爱好，含饴弄孙享清福", effect: (s) => { add(s, "mood", 8); add(s, "health", 4); add(s, "stress", -10); add(s, "cash", -2000); return "你把脚步彻底慢了下来，开始享受那些奋斗时想都不敢想的清福。清晨在阳台侍弄花草，午后跟老伙计们在树荫下杀几盘棋，傍晚牵着咿呀学语的小孙子在小区里溜达。那些年轻时总说「等有空了再做」的事，如今一桩桩、一件件慢慢补了回来。日子被你过成了一首散淡的诗——这份来之不易的悠闲，正是你奔忙了半生，最该得的那枚奖章。"; } },
      { label: "周游世界，看没看过的风景", effect: (s) => { add(s, "cash", -15000); add(s, "mood", 10); add(s, "insight", 3); add(s, "health", -2); add(s, "body", 1); return "你不想让晚年困在方寸之间，于是收拾起行囊，圆了那个搁置了大半辈子的梦——去看世界。你走过陌生的国度，登过年轻时只在画册里见过的山，站在异乡的海边任风吹乱花白的头发。一路下来，腿脚是比从前累了，时差也得倒上几天。可你眼里盛着的风景、心里装下的辽阔，远比银行账户上那串数字，要丰盈、要动人得多。"; } },
      { label: "回馈社会，做志愿 / 传帮带", effect: (s) => { add(s, "reputation", 5); add(s, "mood", 6); add(s, "network", 3); add(s, "health", -1); return "操劳半生攒下的经验和那身没处使的余力，你不想就这么闲置着。于是你走进社区做起了志愿者，或是带起了一批初出茅庐的年轻后辈，把毕生的本事和处世的道理，毫无保留地传下去。你不图名、不图利，只图一份内心的踏实。而正是这份「我依然被人需要」的笃定与暖意，让你的晚年活得格外有重量、有光彩——人这一生，能成全别人，何尝不是成全自己。"; } }
    ] }
);
